import subprocess, os
files=subprocess.check_output(['git','ls-files'], text=True).splitlines()
text_ext={'.ts','.tsx','.md','.json','.mjs','.js','.yml','.yaml','.css','.sql','.sh','.example'}
mods=['apps/web','services/auth','services/workspace','services/runtime','services/agent','services/memory','services/publish','services/browser','packages/db','packages/shared','docs','.planning','scripts','infra']
for prefix in mods:
    total=0; count=0
    for f in files:
        if f.startswith(prefix+'/') and os.path.splitext(f)[1] in text_ext:
            try:
                with open(f,'rb') as fh: total += fh.read().count(b'\n')+1
                count+=1
            except Exception: pass
    print(f'{prefix:25s} files={count:3d} lines={total:7d}')
