interface SnapshotArchive {
  version: number;
  workspaceId: string;
  createdAt: string;
  files: Array<{
    path: string;
    name: string;
    parentPath: string | null;
    isDirectory: boolean;
    mimeType: string | null;
    size: number;
    contentBase64: string | null;
  }>;
}

