import { AnthropicProvider } from './anthropic';
import { OpenAIProvider } from './openai';
import { LLMProvider } from './types';

const DEFAULT_OPENAI_MODEL = 'gpt-4-turbo-preview';
const DEFAULT_ANTHROPIC_MODEL = 'claude-3-opus-20240229';
const DEFAULT_MINIMAX_MODEL = 'MiniMax-M2.7';
const DEFAULT_MINIMAX_BASE_URL = 'https://api.minimax.io/anthropic';

export type LLMProviderName = 'openai' | 'anthropic' | 'minimax';

export function createLLMProvider(env: NodeJS.ProcessEnv = process.env): LLMProvider {
  const provider = normalizeProviderName(env.LLM_PROVIDER);

  if (provider === 'minimax') {
    return new AnthropicProvider(
      env.MINIMAX_TOKEN_PLAN_API_KEY || env.MINIMAX_API_KEY || developmentProviderKey('minimax'),
      env.MINIMAX_MODEL || DEFAULT_MINIMAX_MODEL,
      env.MINIMAX_BASE_URL || DEFAULT_MINIMAX_BASE_URL,
      'bearer',
      'minimax',
    );
  }

  if (provider === 'anthropic') {
    return new AnthropicProvider(
      env.ANTHROPIC_API_KEY || developmentProviderKey('anthropic'),
      env.ANTHROPIC_MODEL || DEFAULT_ANTHROPIC_MODEL,
      env.ANTHROPIC_BASE_URL,
    );
  }

  return new OpenAIProvider(
    env.OPENAI_API_KEY || developmentProviderKey('openai'),
    env.OPENAI_MODEL || DEFAULT_OPENAI_MODEL,
  );
}

function normalizeProviderName(value: string | undefined): LLMProviderName {
  if (value === 'anthropic' || value === 'minimax' || value === 'openai') {
    return value;
  }

  return 'openai';
}

function developmentProviderKey(provider: LLMProviderName): string {
  if (process.env.NODE_ENV === 'production') {
    throw new Error(
      `Missing required LLM API key for provider "${provider}" in production. ` +
        `Set OPENAI_API_KEY, ANTHROPIC_API_KEY, or MINIMAX_TOKEN_PLAN_API_KEY.`,
    );
  }
  return `dev-${provider}-api-key`;
}

export interface Message {
  role: 'system' | 'user' | 'assistant';
  content: string;
  name?: string; // e.g. for tool responses
}

export interface ToolDefinition {
  name: string;
  description: string;
  parameters: Record<string, any>; // JSON Schema object
}

export interface ToolCall {
  id: string;
  name: string;
  arguments: string; // JSON string
}

export interface LLMResponse {
  content: string | null;
  toolCalls?: ToolCall[];
  usage?: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  };
}

export interface LLMProvider {
  readonly providerName: string;
  readonly modelName: string;
  generate(messages: Message[], tools?: ToolDefinition[]): Promise<LLMResponse>;
}

interface RetryOptions {
  maxRetries?: number;
  baseDelayMs?: number;
  maxDelayMs?: number;
  retryableStatusCodes?: number[];
  retryableCodes?: string[];
  logger?: { warn: (...args: unknown[]) => void };
  label?: string;
}

function isRetryableError(
  error: unknown,
  statusCodes: number[],
  errorCodes: string[],
): boolean {
  if (error instanceof Error) {
    const code = (error as Error & { code?: unknown }).code;
    if (typeof code === 'string' && errorCodes.includes(code)) {
      return true;
    }
  }

  const status = typeof error === 'object' && error !== null ? (error as { status?: unknown }).status : undefined;
  if (typeof status === 'number' && statusCodes.includes(status)) {
    return true;
  }

  return false;
}

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export async function withRetry<T>(fn: () => Promise<T>, options: RetryOptions = {}): Promise<T> {
  const {
    maxRetries = 3,
    baseDelayMs = 1000,
    maxDelayMs = 32000,
    retryableStatusCodes = [429, 500, 502, 503, 504],
    retryableCodes = ['ECONNRESET', 'ETIMEDOUT', 'ECONNREFUSED', 'ENOTFOUND'],
    logger,
    label,
  } = options;

  let lastError: unknown;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;

      if (attempt === maxRetries) {
        break;
      }

      if (!isRetryableError(error, retryableStatusCodes, retryableCodes)) {
        throw error;
      }

      const backoffMs = Math.min(baseDelayMs * 2 ** attempt, maxDelayMs);
      const jitteredMs = backoffMs + Math.random() * backoffMs * 0.5;

      logger?.warn(
        { attempt: attempt + 1, maxRetries, delayMs: Math.round(jitteredMs), label },
        'LLM call failed, retrying',
      );

      await delay(jitteredMs);
    }
  }

  throw lastError;
}

import OpenAI from 'openai';
import { LLMProvider, Message, ToolDefinition, LLMResponse } from './types';
import { withRetry } from './withRetry';

function toOpenAIRole(role: Message['role']): 'system' | 'user' | 'assistant' {
  return role;
}

export class OpenAIProvider implements LLMProvider {
  readonly providerName = 'openai';
  readonly modelName: string;
  private client: OpenAI;

  constructor(apiKey: string, model: string = 'gpt-4-turbo-preview') {
    this.client = new OpenAI({ apiKey });
    this.modelName = model;
  }

  async generate(messages: Message[], tools?: ToolDefinition[]): Promise<LLMResponse> {
    return withRetry(() => this._generate(messages, tools), {
      label: 'OpenAIProvider',
      maxRetries: 3,
      baseDelayMs: 1000,
    });
  }

  private async _generate(messages: Message[], tools?: ToolDefinition[]): Promise<LLMResponse> {
    const formattedMessages = messages.map(m => ({
      role: toOpenAIRole(m.role),
      content: m.content,
      name: m.name,
    }));

    const formattedTools = tools?.map(t => ({
      type: 'function' as const,
      function: {
        name: t.name,
        description: t.description,
        parameters: t.parameters,
      }
    }));

    const response = await this.client.chat.completions.create({
      model: this.modelName,
      messages: formattedMessages,
      tools: formattedTools,
      tool_choice: formattedTools ? 'auto' : 'none',
    });

    const choice = response.choices[0];
    if (!choice) throw new Error('No choice returned from OpenAI');
    const message = choice.message;

    const toolCalls = message.tool_calls?.map(tc => ({
      id: tc.id,
      name: tc.function.name,
      arguments: tc.function.arguments,
    }));

    return {
      content: message.content,
      toolCalls,
      usage: response.usage ? {
        promptTokens: response.usage.prompt_tokens,
        completionTokens: response.usage.completion_tokens,
        totalTokens: response.usage.total_tokens,
      } : undefined,
    };
  }
}

import Anthropic from '@anthropic-ai/sdk';
import { LLMProvider, Message, ToolDefinition, LLMResponse, ToolCall } from './types';
import { withRetry } from './withRetry';

type AnthropicAuthMode = 'api-key' | 'bearer';

function toAnthropicRole(role: Message['role']): 'user' | 'assistant' {
  return role === 'assistant' ? 'assistant' : 'user';
}

function toAnthropicInputSchema(parameters: ToolDefinition['parameters']) {
  return {
    type: 'object' as const,
    ...parameters,
  };
}

export class AnthropicProvider implements LLMProvider {
  readonly providerName: string;
  readonly modelName: string;
  private client: Anthropic;

  constructor(
    apiKey: string,
    model: string = 'claude-3-opus-20240229',
    baseURL?: string,
    authMode: AnthropicAuthMode = 'api-key',
    providerNameParam = 'anthropic',
  ) {
    this.client = new Anthropic({
      apiKey: authMode === 'api-key' ? apiKey : null,
      authToken: authMode === 'bearer' ? apiKey : null,
      baseURL,
    });
    this.modelName = model;
    this.providerName = providerNameParam;
  }

  async generate(messages: Message[], tools?: ToolDefinition[]): Promise<LLMResponse> {
    return withRetry(() => this._generate(messages, tools), {
      label: 'AnthropicProvider',
      maxRetries: 3,
      baseDelayMs: 1000,
    });
  }

  private async _generate(messages: Message[], tools?: ToolDefinition[]): Promise<LLMResponse> {
    const formattedMessages = messages.filter(m => m.role !== 'system').map(m => ({
      role: toAnthropicRole(m.role),
      content: m.content,
    }));

    const systemMessage = messages.find(m => m.role === 'system')?.content;

    const formattedTools = tools?.map(t => ({
      name: t.name,
      description: t.description,
      input_schema: toAnthropicInputSchema(t.parameters),
    }));

    const response = await this.client.messages.create({
      model: this.modelName,
      max_tokens: 4096,
      system: systemMessage,
      messages: formattedMessages,
      tools: formattedTools,
    });

    let contentStr = null;
    const toolCalls: ToolCall[] = [];

    for (const block of response.content) {
      if (block.type === 'text') {
        contentStr = block.text;
      } else if (block.type === 'tool_use') {
        toolCalls.push({
          id: block.id,
          name: block.name,
          arguments: JSON.stringify(block.input),
        });
      }
    }

    return {
      content: contentStr,
      toolCalls: toolCalls.length > 0 ? toolCalls : undefined,
      usage: {
        promptTokens: response.usage.input_tokens,
        completionTokens: response.usage.output_tokens,
        totalTokens: response.usage.input_tokens + response.usage.output_tokens,
      },
    };
  }
}

import crypto from 'crypto';
import { db } from '@pcp/db/src/client';
import { providerCredentials, userPreferences } from '@pcp/db/src/schema';
import { and, desc, eq, isNull } from 'drizzle-orm';
import { createLLMProvider, type LLMProviderName } from './provider';
import type { LLMProvider } from './types';
import { env } from '../env';

const ALGORITHM = 'aes-256-gcm';

/**
 * Resolve a per-user `LLMProvider` based on the user's saved preferences and
 * encrypted provider credentials. Returns `null` when the user has no usable
 * configuration so the caller can fall back to the service-wide default.
 */
export async function resolveUserProvider(userId: string): Promise<{
  provider: LLMProvider;
  providerName: LLMProviderName;
  model: string | null;
} | null> {
  if (!userId) return null;

  const prefs = await db.query.userPreferences.findFirst({
    where: eq(userPreferences.userId, userId),
  });

  const providerName = normalizeProviderName(prefs?.defaultProvider ?? null);
  if (!providerName) return null;

  const credential = await db.query.providerCredentials.findFirst({
    where: and(
      eq(providerCredentials.userId, userId),
      eq(providerCredentials.provider, providerName),
      isNull(providerCredentials.revokedAt),
    ),
    orderBy: [desc(providerCredentials.createdAt)],
  });

  if (!credential) return null;

  const apiKey = safeDecrypt(credential.encryptedKey, credential.iv, credential.authTag);
  if (!apiKey) return null;

  // Touch lastUsedAt fire-and-forget; never block the LLM call on this.
  db.update(providerCredentials)
    .set({ lastUsedAt: new Date() })
    .where(eq(providerCredentials.id, credential.id))
    .execute()
    .catch(() => {
      /* best-effort */
    });

  const model = prefs?.defaultModel?.trim() || null;
  const overlay: NodeJS.ProcessEnv = { ...process.env, LLM_PROVIDER: providerName };
  if (providerName === 'openai') {
    overlay.OPENAI_API_KEY = apiKey;
    if (model) overlay.OPENAI_MODEL = model;
  } else if (providerName === 'anthropic') {
    overlay.ANTHROPIC_API_KEY = apiKey;
    if (model) overlay.ANTHROPIC_MODEL = model;
  } else if (providerName === 'minimax') {
    overlay.MINIMAX_API_KEY = apiKey;
    overlay.MINIMAX_TOKEN_PLAN_API_KEY = apiKey;
    if (model) overlay.MINIMAX_MODEL = model;
  }

  const provider = createLLMProvider(overlay);
  return { provider, providerName, model };
}

function normalizeProviderName(value: string | null): LLMProviderName | null {
  if (value === 'openai' || value === 'anthropic' || value === 'minimax') return value;
  return null;
}

function safeDecrypt(encrypted: string, ivBase64: string, authTagBase64: string): string | null {
  const rawKey = env.ENCRYPTION_KEY;
  if (!rawKey) return null;
  const keyBuffer = Buffer.from(rawKey, 'utf8');
  if (keyBuffer.length !== 32) return null;
  try {
    const iv = Buffer.from(ivBase64, 'base64');
    const authTag = Buffer.from(authTagBase64, 'base64');
    const decipher = crypto.createDecipheriv(ALGORITHM, keyBuffer, iv);
    decipher.setAuthTag(authTag);
    let decrypted = decipher.update(encrypted, 'base64', 'utf8');
    decrypted += decipher.final('utf8');
    return decrypted;
  } catch {
    return null;
  }
}

