import { db } from '@pcp/db/src/client';
import { personas } from '@pcp/db/src/schema';
import { and, eq } from 'drizzle-orm';
import type { CreatePersonaDto, UpdatePersonaDto } from '@pcp/shared';

export class PersonasService {
  async list(userId: string) {
    return db.query.personas.findMany({
      where: eq(personas.userId, userId),
      orderBy: (p, { desc, asc }) => [desc(p.isDefault), asc(p.name)],
    });
  }

  async get(id: string, userId: string) {
    const row = await db.query.personas.findFirst({
      where: and(eq(personas.id, id), eq(personas.userId, userId)),
    });
    return row ?? null;
  }

  async getDefault(userId: string) {
    return db.query.personas.findFirst({
      where: and(eq(personas.userId, userId), eq(personas.isDefault, true)),
    });
  }

  async create(userId: string, dto: CreatePersonaDto) {
    const existing = await db.query.personas.findFirst({
      where: and(eq(personas.userId, userId), eq(personas.slug, dto.slug)),
    });
    if (existing) {
      throw Object.assign(new Error('Persona slug already exists'), { statusCode: 409 });
    }

    if (dto.isDefault) {
      await db
        .update(personas)
        .set({ isDefault: false })
        .where(eq(personas.userId, userId));
    }

    const [row] = await db
      .insert(personas)
      .values({
        userId,
        slug: dto.slug,
        name: dto.name,
        systemPrompt: dto.systemPrompt,
        icon: dto.icon ?? null,
        isDefault: dto.isDefault ?? false,
      })
      .returning();
    if (!row) throw new Error('Failed to create persona');
    return row;
  }

  async update(id: string, userId: string, dto: UpdatePersonaDto) {
    const current = await this.get(id, userId);
    if (!current) throw Object.assign(new Error('Persona not found'), { statusCode: 404 });

    if (dto.isDefault) {
      await db
        .update(personas)
        .set({ isDefault: false })
        .where(eq(personas.userId, userId));
    }

    const patch: Record<string, unknown> = { updatedAt: new Date() };
    if (dto.name !== undefined) patch.name = dto.name;
    if (dto.systemPrompt !== undefined) patch.systemPrompt = dto.systemPrompt;
    if (dto.icon !== undefined) patch.icon = dto.icon;
    if (dto.isDefault !== undefined) patch.isDefault = dto.isDefault;

    const [row] = await db
      .update(personas)
      .set(patch)
      .where(and(eq(personas.id, id), eq(personas.userId, userId)))
      .returning();
    if (!row) throw new Error('Failed to update persona');
    return row;
  }

  async remove(id: string, userId: string) {
    const current = await this.get(id, userId);
    if (!current) throw Object.assign(new Error('Persona not found'), { statusCode: 404 });
    await db
      .delete(personas)
      .where(and(eq(personas.id, id), eq(personas.userId, userId)));
    return { success: true };
  }
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import {
  createSkillSchema,
  skillResponseSchema,
  updateSkillSchema,
  apiErrorCodeFromStatus,
  sendApiError,
} from '@pcp/shared';
import { SkillsService } from '../skills/service';
import { SKILL_CATALOG } from '../skills/catalog';
import { AgentOrchestrator } from '../orchestrator';
import { env } from '../env';

export async function setupSkillsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const service = new SkillsService();
  const orchestrator = new AgentOrchestrator(fastify.log);

  async function getUserId(sessionId: string | undefined): Promise<string | null> {
    if (env.AUTH_BYPASS) return 'local-dev-user';
    if (!sessionId) return null;
    return orchestrator.validateUserFromCookie(sessionId);
  }

  server.get(
    '/skills',
    { schema: { response: { 200: z.object({ skills: z.array(skillResponseSchema) }) } } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await service.list(userId);
      return { skills: rows };
    },
  );

  server.post(
    '/skills',
    { schema: { body: createSkillSchema, response: { 201: skillResponseSchema } } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const row = await service.create(userId, request.body);
        return reply.code(201).send(row);
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to create skill',
        );
      }
    },
  );

  server.patch(
    '/skills/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateSkillSchema,
        response: { 200: skillResponseSchema },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const row = await service.update(request.params.id, userId, request.body);
        return row;
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to update skill',
        );
      }
    },
  );

  server.delete(
    '/skills/:id',
    { schema: { params: z.object({ id: z.string().uuid() }) } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await service.remove(request.params.id, userId);
        return { success: true };
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to delete skill',
        );
      }
    },
  );

  // Built-in catalog of preset skills the user can one-click install.
  server.get(
    '/skills/catalog',
    {
      schema: {
        response: {
          200: z.object({
            skills: z.array(
              z.object({
                slug: z.string(),
                name: z.string(),
                description: z.string(),
                category: z.string(),
                triggers: z.array(z.string()),
                bodyMarkdown: z.string(),
                installed: z.boolean(),
              }),
            ),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const installed = await service.list(userId);
      const installedSlugs = new Set(installed.map((s) => s.slug));
      return {
        skills: SKILL_CATALOG.map((s) => ({ ...s, installed: installedSlugs.has(s.slug) })),
      };
    },
  );

  // Install a preset skill into the user's library by slug.
  server.post(
    '/skills/install',
    {
      schema: {
        body: z.object({ slug: z.string().min(1).max(120) }),
        response: { 201: skillResponseSchema },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const preset = SKILL_CATALOG.find((s) => s.slug === request.body.slug);
      if (!preset) return sendApiError(reply, 404, 'NOT_FOUND', 'Catalog skill not found');
      try {
        const row = await service.create(userId, {
          slug: preset.slug,
          name: preset.name,
          description: preset.description,
          bodyMarkdown: preset.bodyMarkdown,
          triggers: preset.triggers,
          enabled: true,
        });
        return reply.code(201).send(row);
      } catch (err: any) {
        const status = err.statusCode ?? 400;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err.message ?? 'Failed to install skill',
        );
      }
    },
  );

  server.post(
    '/skills/match',
    {
      schema: {
        body: z.object({ input: z.string().min(1).max(20000) }),
        response: { 200: z.object({ skills: z.array(skillResponseSchema) }) },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const matched = await service.matchTriggers(userId, request.body.input);
      return { skills: matched };
    },
  );
}

import { db } from '@pcp/db/src/client';
import { skills } from '@pcp/db/src/schema';
import { and, eq, isNull, inArray } from 'drizzle-orm';
import type { CreateSkillDto, UpdateSkillDto } from '@pcp/shared';

export class SkillsService {
  async list(userId: string) {
    return db.query.skills.findMany({
      where: and(eq(skills.userId, userId), isNull(skills.deletedAt)),
      orderBy: (s, { asc }) => [asc(s.name)],
    });
  }

  async get(id: string, userId: string) {
    return db.query.skills.findFirst({
      where: and(eq(skills.id, id), eq(skills.userId, userId), isNull(skills.deletedAt)),
    });
  }

  async getMany(ids: string[], userId: string) {
    if (ids.length === 0) return [];
    return db.query.skills.findMany({
      where: and(
        inArray(skills.id, ids),
        eq(skills.userId, userId),
        eq(skills.enabled, true),
        isNull(skills.deletedAt),
      ),
    });
  }

  async create(userId: string, dto: CreateSkillDto) {
    const existing = await db.query.skills.findFirst({
      where: and(
        eq(skills.userId, userId),
        eq(skills.slug, dto.slug),
        isNull(skills.deletedAt),
      ),
    });
    if (existing) {
      throw Object.assign(new Error('Skill slug already exists'), { statusCode: 409 });
    }

    const [row] = await db
      .insert(skills)
      .values({
        userId,
        workspaceId: dto.workspaceId ?? null,
        slug: dto.slug,
        name: dto.name,
        description: dto.description ?? null,
        bodyMarkdown: dto.bodyMarkdown ?? null,
        sourcePath: dto.sourcePath ?? null,
        triggers: dto.triggers ?? [],
        enabled: dto.enabled ?? true,
      })
      .returning();
    if (!row) throw new Error('Failed to create skill');
    return row;
  }

  async update(id: string, userId: string, dto: UpdateSkillDto) {
    const current = await this.get(id, userId);
    if (!current) throw Object.assign(new Error('Skill not found'), { statusCode: 404 });
    const patch: Record<string, unknown> = { updatedAt: new Date() };
    if (dto.name !== undefined) patch.name = dto.name;
    if (dto.description !== undefined) patch.description = dto.description;
    if (dto.bodyMarkdown !== undefined) patch.bodyMarkdown = dto.bodyMarkdown;
    if (dto.triggers !== undefined) patch.triggers = dto.triggers;
    if (dto.enabled !== undefined) patch.enabled = dto.enabled;

    const [row] = await db
      .update(skills)
      .set(patch)
      .where(and(eq(skills.id, id), eq(skills.userId, userId)))
      .returning();
    if (!row) throw new Error('Failed to update skill');
    return row;
  }

  async remove(id: string, userId: string) {
    const current = await this.get(id, userId);
    if (!current) throw Object.assign(new Error('Skill not found'), { statusCode: 404 });
    await db
      .update(skills)
      .set({ deletedAt: new Date() })
      .where(and(eq(skills.id, id), eq(skills.userId, userId)));
    return { success: true };
  }

  /**
   * Match enabled skills against a user input. Returns skills whose triggers
   * (case-insensitive substring match) appear in the input. Used to suggest
   * skills before a task starts.
   */
  async matchTriggers(userId: string, input: string) {
    const all = await db.query.skills.findMany({
      where: and(
        eq(skills.userId, userId),
        eq(skills.enabled, true),
        isNull(skills.deletedAt),
      ),
    });
    const lower = input.toLowerCase();
    return all.filter((s) =>
      (s.triggers ?? []).some((t) => t && lower.includes(t.toLowerCase())),
    );
  }
}

import { Queue, Worker, Job } from 'bullmq';
import IORedis from 'ioredis';
import { db } from '@pcp/db/src/client';
import { automations, automationRuns, workspaces } from '@pcp/db/src/schema';
import { and, eq, isNull } from 'drizzle-orm';
import { AgentOrchestrator } from '../orchestrator';
import { env } from '../env';
import { dispatchAutomationRunNotification } from './notify';

// Initialize Redis connection
const connection = new IORedis(env.REDIS_URL, { maxRetriesPerRequest: null });

export const automationQueue = new Queue('automations', { connection });

export async function setupAutomationWorker(orchestrator: AgentOrchestrator, logger: any) {
  const worker = new Worker(
    'automations',
    async (job: Job) => {
      const { runId, automationId, userId, workspaceId, prompt } = await resolveAutomationJobData(
        job.data,
      );

      logger.info({ runId, automationId }, 'Processing automation run');

      const startedAt = new Date();
      // Update run status to running
      await db
        .update(automationRuns)
        .set({ status: 'running', startedAt })
        .where(eq(automationRuns.id, runId));

      const automation = await db.query.automations.findFirst({
        where: eq(automations.id, automationId),
      });

      try {
        // Pass it to AgentOrchestrator to run
        const task = await orchestrator.createTask(userId, workspaceId, prompt);

        // Update run with taskId
        await db
          .update(automationRuns)
          .set({ taskId: task.id })
          .where(eq(automationRuns.id, runId));

        // In a real long-running scenario, we would wait for task completion.
        // For now, since the task executes asynchronously or synchronously, we just mark it as completed.
        // If we need the actual task output, we can poll or hook into task completion events.
        const finishedAt = new Date();
        const durationMs = finishedAt.getTime() - startedAt.getTime();
        await db
          .update(automationRuns)
          .set({
            status: 'completed',
            finishedAt,
            durationMs: durationMs.toString(),
            notificationSent: true,
          })
          .where(eq(automationRuns.id, runId));

        await db
          .update(automations)
          .set({ lastRunAt: finishedAt })
          .where(eq(automations.id, automationId));

        logger.info({ runId }, 'Automation run completed');

        if (automation) {
          await dispatchAutomationRunNotification(
            {
              runId,
              automationId,
              userId,
              title: automation.title,
              status: 'completed',
              durationMs,
              output: null,
            },
            {
              mode: automation.notificationMode,
              webhookUrl: automation.webhookUrl,
              logger,
            },
          );
        }
      } catch (error) {
        logger.error({ runId, error }, 'Automation run failed');
        const finishedAt = new Date();
        const durationMs = finishedAt.getTime() - startedAt.getTime();
        const message = error instanceof Error ? error.message : 'Unknown error';
        await db
          .update(automationRuns)
          .set({
            status: 'failed',
            finishedAt,
            durationMs: durationMs.toString(),
            error: message,
            notificationSent: true,
          })
          .where(eq(automationRuns.id, runId));

        if (automation) {
          await dispatchAutomationRunNotification(
            {
              runId,
              automationId,
              userId,
              title: automation.title,
              status: 'failed',
              durationMs,
              error: message,
            },
            {
              mode: automation.notificationMode,
              webhookUrl: automation.webhookUrl,
              logger,
            },
          );
        }
      }
    },
    { connection },
  );

  worker.on('failed', (job, err) => {
    logger.error({ jobId: job?.id, err }, 'Automation job failed');
  });

  return worker;
}

async function resolveAutomationJobData(data: {
  runId?: string;
  automationId?: string;
  userId?: string;
  workspaceId?: string | null;
  prompt?: string;
}) {
  if (data.runId && data.automationId && data.userId && data.workspaceId && data.prompt) {
    await assertWorkspaceOwned(data.userId, data.workspaceId);
    return data as {
      runId: string;
      automationId: string;
      userId: string;
      workspaceId: string;
      prompt: string;
    };
  }

  if (!data.automationId) {
    throw new Error('Automation job is missing automationId');
  }

  const automation = await db.query.automations.findFirst({
    where: eq(automations.id, data.automationId),
  });

  if (!automation || !automation.enabled) {
    throw new Error('Automation not found or disabled');
  }

  if (!automation.workspaceId) {
    throw new Error('Automation workspace is required to run');
  }

  await assertWorkspaceOwned(automation.userId, automation.workspaceId);

  const [run] = await db
    .insert(automationRuns)
    .values({
      automationId: automation.id,
      userId: automation.userId,
      trigger: 'schedule',
      status: 'queued',
    })
    .returning();

  if (!run) {
    throw new Error('Failed to create automation run');
  }

  return {
    runId: run.id,
    automationId: automation.id,
    userId: automation.userId,
    workspaceId: automation.workspaceId,
    prompt: automation.prompt,
  };
}

async function assertWorkspaceOwned(userId: string, workspaceId: string): Promise<void> {
  const workspace = await db.query.workspaces.findFirst({
    where: and(
      eq(workspaces.id, workspaceId),
      eq(workspaces.userId, userId),
      isNull(workspaces.deletedAt),
    ),
  });
  if (!workspace) throw new Error('Automation workspace not found');
}

/**
 * Schedule helpers for automations. Translates user-facing scheduleType values
 * (manual | hourly | daily | weekly | cron) into BullMQ repeat patterns and
 * computes the next-run timestamp for UI display.
 *
 * For "cron" we use the user-supplied expression as-is and intentionally do
 * NOT compute nextRunAt locally (avoids pulling in a cron parser dependency).
 * BullMQ owns the actual schedule.
 */

export interface AutomationScheduleInput {
  scheduleType: string;
  cronExpression?: string | null;
  timezone?: string | null;
}

export interface ResolvedSchedule {
  /** True when the automation should be enqueued as a repeating BullMQ job. */
  isRepeating: boolean;
  /** Cron-like pattern accepted by BullMQ `repeat.pattern`. */
  pattern?: string;
  /** Optional IANA timezone forwarded to BullMQ. */
  timezone?: string;
}

/**
 * Resolve the BullMQ repeat configuration for an automation.
 * Returns `{ isRepeating: false }` for manual or invalid configs.
 */
export function resolveSchedule(input: AutomationScheduleInput): ResolvedSchedule {
  const tz = input.timezone || undefined;
  switch (input.scheduleType) {
    case 'hourly':
      return { isRepeating: true, pattern: '0 * * * *', timezone: tz };
    case 'daily':
      return { isRepeating: true, pattern: '0 9 * * *', timezone: tz };
    case 'weekly':
      return { isRepeating: true, pattern: '0 9 * * 1', timezone: tz };
    case 'cron':
      if (input.cronExpression && input.cronExpression.trim().length > 0) {
        return { isRepeating: true, pattern: input.cronExpression.trim(), timezone: tz };
      }
      return { isRepeating: false };
    default:
      return { isRepeating: false };
  }
}

/**
 * Best-effort next-run estimate used purely for UI display. Accurate for
 * hourly/daily/weekly; returns null for cron expressions (BullMQ owns truth).
 */
export function computeNextRunAt(
  input: AutomationScheduleInput,
  from: Date = new Date(),
): Date | null {
  switch (input.scheduleType) {
    case 'hourly': {
      const next = new Date(from);
      next.setMinutes(0, 0, 0);
      next.setHours(next.getHours() + 1);
      return next;
    }
    case 'daily': {
      const next = new Date(from);
      next.setHours(9, 0, 0, 0);
      if (next.getTime() <= from.getTime()) {
        next.setDate(next.getDate() + 1);
      }
      return next;
    }
    case 'weekly': {
      const next = new Date(from);
      next.setHours(9, 0, 0, 0);
      const dow = next.getDay(); // 0 Sun .. 6 Sat
      // Target Monday (1).
      const daysAhead = (1 - dow + 7) % 7 || (next.getTime() <= from.getTime() ? 7 : 0);
      next.setDate(next.getDate() + daysAhead);
      if (next.getTime() <= from.getTime()) next.setDate(next.getDate() + 7);
      return next;
    }
    default:
      return null;
  }
}

export const AUTOMATION_REPEAT_JOB_PREFIX = 'automation-';

export function automationRepeatKey(automationId: string): string {
  return `${AUTOMATION_REPEAT_JOB_PREFIX}${automationId}`;
}

import { createHmac, timingSafeEqual } from 'node:crypto';
import { db } from '@pcp/db/src/client';
import { notifications } from '@pcp/db/src/schema';
import { env } from '../env';

export interface AutomationRunSummary {
  runId: string;
  automationId: string;
  userId: string;
  title: string;
  status: 'completed' | 'failed';
  durationMs?: number;
  error?: string | null;
  output?: string | null;
}

export interface NotifyOptions {
  /** Notification mode set on the automation: 'none' | 'in-app' | 'email-mock' | 'webhook'. */
  mode: string;
  /** Optional webhook URL when mode === 'webhook'. */
  webhookUrl?: string | null;
  /** Optional logger. */
  logger?: { info: (...a: any[]) => void; warn: (...a: any[]) => void; error: (...a: any[]) => void };
}

const WEBHOOK_TIMEOUT_MS = 10_000;

/**
 * Dispatch a notification for an automation run completion. Always inserts a
 * row into the `notifications` table (so the in-app badge counts every run),
 * and additionally fans out to the configured channel (webhook / email-mock).
 *
 * Failures in fan-out are logged but never thrown — the automation worker
 * should not crash because of a misconfigured destination.
 */
export async function dispatchAutomationRunNotification(
  run: AutomationRunSummary,
  opts: NotifyOptions,
): Promise<void> {
  const logger = opts.logger;
  const severity = run.status === 'completed' ? 'success' : 'error';

  const inAppTitle =
    run.status === 'completed'
      ? `Automation finished: ${run.title}`
      : `Automation failed: ${run.title}`;
  const inAppBody =
    run.status === 'completed'
      ? truncate(run.output ?? '', 500) || 'Run completed without output.'
      : truncate(run.error ?? 'Unknown error', 500);

  try {
    await db.insert(notifications).values({
      userId: run.userId,
      kind: 'automation_run',
      title: inAppTitle,
      body: inAppBody,
      severity,
      link: `/automations/${run.automationId}`,
      payload: {
        automationId: run.automationId,
        runId: run.runId,
        status: run.status,
      },
    });
  } catch (err) {
    logger?.warn({ err, runId: run.runId }, 'Failed to insert in-app notification');
  }

  if (opts.mode === 'webhook' && opts.webhookUrl) {
    await sendWebhook(opts.webhookUrl, run, logger);
  } else if (opts.mode === 'email-mock') {
    logger?.info(
      { runId: run.runId, userId: run.userId, status: run.status },
      'email-mock: would send automation run email',
    );
  }
}

async function sendWebhook(
  url: string,
  run: AutomationRunSummary,
  logger: NotifyOptions['logger'],
): Promise<void> {
  const body = JSON.stringify({
    type: 'automation_run',
    runId: run.runId,
    automationId: run.automationId,
    title: run.title,
    status: run.status,
    durationMs: run.durationMs,
    error: run.error ?? null,
    output: run.output ?? null,
    timestamp: new Date().toISOString(),
  });

  const signature = createHmac('sha256', env.INTERNAL_SERVICE_TOKEN).update(body).digest('hex');

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), WEBHOOK_TIMEOUT_MS);
  try {
    const res = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-Pcp-Event': 'automation_run',
        'X-Pcp-Signature': `sha256=${signature}`,
      },
      body,
      signal: controller.signal,
    });
    if (!res.ok) {
      const text = await res.text().catch(() => '');
      logger?.warn({ runId: run.runId, status: res.status, text: truncate(text, 200) }, 'Webhook returned non-2xx');
    }
  } catch (err) {
    logger?.warn({ err, runId: run.runId }, 'Webhook delivery failed');
  } finally {
    clearTimeout(timer);
  }
}

/**
 * Compute the HMAC token used to validate inbound automation webhook triggers.
 * Token is shared per-automation and stable across server restarts (because
 * INTERNAL_SERVICE_TOKEN is stable).
 */
export function automationTriggerToken(automationId: string): string {
  return createHmac('sha256', env.INTERNAL_SERVICE_TOKEN)
    .update(`automation-trigger:${automationId}`)
    .digest('hex')
    .slice(0, 32);
}

/**
 * Constant-time comparison of an inbound trigger token against the expected
 * value for the given automation.
 */
export function verifyAutomationTriggerToken(automationId: string, token: string): boolean {
  const expected = Buffer.from(automationTriggerToken(automationId));
  const actual = Buffer.from(token);
  if (expected.length !== actual.length) return false;
  return timingSafeEqual(expected, actual);
}

function truncate(value: string, max: number): string {
  if (value.length <= max) return value;
  return value.slice(0, max) + '…';
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { db } from '@pcp/db/src/client';
import { channelLinks, auditLogs, workspaces } from '@pcp/db/src/schema';
import { and, eq, isNull } from 'drizzle-orm';
import {
  channelLinkResponseSchema,
  createChannelLinkSchema,
  updateChannelLinkSchema,
  sendApiError,
} from '@pcp/shared';
import { AgentOrchestrator } from '../orchestrator';
import { TelegramAdapter } from '../channels/telegram';
import { handleIncoming } from '../channels/router';
import { env } from '../env';

type TelegramWebhookUpdate = {
  message?: {
    text?: string;
    chat?: { id?: string | number };
    from?: {
      id?: string | number;
      username?: string;
      first_name?: string;
      last_name?: string;
    };
  };
};

/**
 * Channel routes: CRUD for channel_links + Telegram webhook receiver.
 */
export async function setupChannelsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const orchestrator = new AgentOrchestrator(fastify.log);
  const telegram = TelegramAdapter.fromEnv();

  async function getUserId(sessionId: string | undefined): Promise<string | null> {
    if (env.AUTH_BYPASS) return 'local-dev-user';
    if (!sessionId) return null;
    return orchestrator.validateUserFromCookie(sessionId);
  }

  async function assertWorkspaceOwned(workspaceId: string | null | undefined, userId: string) {
    if (!workspaceId) return true;
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });
    return Boolean(workspace);
  }

  // List my channel links
  server.get(
    '/channels/links',
    {
      schema: {
        response: { 200: z.object({ links: z.array(channelLinkResponseSchema) }) },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await db.query.channelLinks.findMany({
        where: eq(channelLinks.userId, userId),
        orderBy: (l, { desc: d }) => [d(l.createdAt)],
      });
      return { links: rows };
    },
  );

  server.post(
    '/channels/links',
    { schema: { body: createChannelLinkSchema, response: { 201: channelLinkResponseSchema } } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const existing = await db.query.channelLinks.findFirst({
        where: and(
          eq(channelLinks.channel, request.body.channel),
          eq(channelLinks.externalId, request.body.externalId),
        ),
      });
      if (existing) {
        return sendApiError(reply, 409, 'CONFLICT', 'This external account is already linked.');
      }

      const [row] = await db
        .insert(channelLinks)
        .values({
          userId,
          channel: request.body.channel,
          externalId: request.body.externalId,
          label: request.body.label ?? null,
          workspaceId: request.body.workspaceId ?? null,
        })
        .returning();
      if (!row) return sendApiError(reply, 500, 'INTERNAL_ERROR', 'Failed to create link');
      try {
        await db.insert(auditLogs).values({
          userId,
          action: 'CHANNEL_LINK_CREATE',
          details: { channel: row.channel, externalId: row.externalId, linkId: row.id },
        });
      } catch {
        /* audit best-effort */
      }
      return reply.code(201).send(row);
    },
  );

  server.patch(
    '/channels/links/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateChannelLinkSchema,
        response: { 200: channelLinkResponseSchema },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }
      const patch: Record<string, unknown> = { updatedAt: new Date() };
      if (request.body.label !== undefined) patch.label = request.body.label;
      if (request.body.workspaceId !== undefined) patch.workspaceId = request.body.workspaceId;
      if (request.body.enabled !== undefined) patch.enabled = request.body.enabled;
      const [row] = await db
        .update(channelLinks)
        .set(patch)
        .where(and(eq(channelLinks.id, request.params.id), eq(channelLinks.userId, userId)))
        .returning();
      if (!row) return sendApiError(reply, 404, 'NOT_FOUND', 'Link not found');
      return row;
    },
  );

  server.delete(
    '/channels/links/:id',
    { schema: { params: z.object({ id: z.string().uuid() }) } },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const result = await db
        .delete(channelLinks)
        .where(and(eq(channelLinks.id, request.params.id), eq(channelLinks.userId, userId)))
        .returning();
      if (result.length === 0) return sendApiError(reply, 404, 'NOT_FOUND', 'Link not found');
      try {
        await db.insert(auditLogs).values({
          userId,
          action: 'CHANNEL_LINK_DELETE',
          details: { linkId: request.params.id },
        });
      } catch {
        /* audit best-effort */
      }
      return { success: true };
    },
  );

  // Status: which adapters are configured (helps the UI render setup hints)
  server.get(
    '/channels/status',
    {
      schema: {
        response: {
          200: z.object({
            telegram: z.object({
              enabled: z.boolean(),
              webhookUrl: z.string().nullable(),
            }),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await getUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      return {
        telegram: {
          enabled: telegram !== null,
          webhookUrl: TelegramAdapter.getWebhookUrl(),
        },
      };
    },
  );

  // Public Telegram webhook. Optional shared-secret header per Telegram Bot API
  // setWebhook `secret_token` parameter (env: TELEGRAM_WEBHOOK_SECRET).
  server.post(
    '/channels/telegram/webhook',
    {
      config: { rateLimit: { max: 60, timeWindow: '1 minute' } },
      schema: {
        body: z.any(),
      },
    },
    async (request, reply) => {
      if (!telegram) return sendApiError(reply, 500, 'INTERNAL_ERROR', 'Telegram not configured');

      const expectedSecret = process.env.TELEGRAM_WEBHOOK_SECRET;
      if (expectedSecret) {
        const got = request.headers['x-telegram-bot-api-secret-token'];
        if (got !== expectedSecret) {
          return sendApiError(reply, 401, 'UNAUTHORIZED', 'Bad secret');
        }
      }

      const update = request.body as TelegramWebhookUpdate;
      const m = update?.message;
      if (!m || !m.text || !m.chat?.id) {
        return reply.send({ ok: true, ignored: true });
      }

      const chatId = String(m.chat.id);
      const fromId = m.from?.id ? String(m.from.id) : chatId;
      const display =
        m.from?.username ||
        [m.from?.first_name, m.from?.last_name].filter(Boolean).join(' ') ||
        undefined;

      // ACK immediately; do the work async so Telegram doesn't retry on slow loops.
      void handleIncoming(
        {
          channel: 'telegram',
          externalUserId: fromId,
          externalThreadId: chatId,
          body: m.text,
          externalDisplayName: display,
          receivedAt: new Date(),
        },
        orchestrator,
        telegram,
        fastify.log,
      ).catch((err) => fastify.log.error({ err }, 'Telegram handleIncoming failed'));

      return reply.send({ ok: true });
    },
  );
}

import { db } from '@pcp/db/src/client';
import { channelLinks, conversations, tasks, workspaces } from '@pcp/db/src/schema';
import { and, desc, eq, isNull } from 'drizzle-orm';
import type { AgentOrchestrator } from '../orchestrator';
import type { ChannelAdapter, IncomingMessage } from './types';

const POLL_INTERVAL_MS = 1500;
const TASK_TIMEOUT_MS = 5 * 60 * 1000; // 5 min

/**
 * Routes an inbound channel message to the agent and replies via the adapter.
 *
 * Steps:
 *  1. Look up channel_links row by (channel, externalId) → repo userId.
 *     If none, ignore (silent — link must be created from /channels first).
 *  2. Find or create the conversation matching (userId, channel, channelThreadId).
 *  3. Enqueue an agent task in the user's default workspace.
 *  4. Poll the task to completion (or timeout).
 *  5. Send the agent's output back via adapter.sendReply.
 */
export async function handleIncoming(
  msg: IncomingMessage,
  orchestrator: AgentOrchestrator,
  adapter: ChannelAdapter,
  logger: { info: Function; warn: Function; error: Function },
): Promise<void> {
  const link = await db.query.channelLinks.findFirst({
    where: and(
      eq(channelLinks.channel, msg.channel),
      eq(channelLinks.externalId, msg.externalUserId),
      eq(channelLinks.enabled, true),
    ),
  });

  if (!link) {
    logger.info(
      { channel: msg.channel, externalUserId: msg.externalUserId },
      'No channel link found; ignoring message',
    );
    try {
      await adapter.sendReply(
        msg.externalThreadId,
        'Bu hesap CloudMind ile eşleştirilmemiş. /channels sayfasından bağla.',
      );
    } catch {
      /* swallow */
    }
    return;
  }

  // Resolve workspace: explicit on the link, else user's first workspace.
  let workspaceId = link.workspaceId;
  if (!workspaceId) {
    const ws = await db.query.workspaces.findFirst({
      where: and(eq(workspaces.userId, link.userId), isNull(workspaces.deletedAt)),
      orderBy: (w, { asc }) => [asc(w.createdAt)],
    });
    if (!ws) {
      await adapter.sendReply(
        msg.externalThreadId,
        'CloudMind hesabınızda henüz bir workspace yok. Web arayüzünden bir tane oluşturun.',
      );
      return;
    }
    workspaceId = ws.id;
  } else {
    const ws = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, link.userId),
        isNull(workspaces.deletedAt),
      ),
    });
    if (!ws) {
      logger.warn({ linkId: link.id, userId: link.userId, workspaceId }, 'Channel link workspace not found');
      await adapter.sendReply(
        msg.externalThreadId,
        'Bu kanalın workspace bağlantısı geçersiz. Web arayüzünden bağlantıyı güncelleyin.',
      );
      return;
    }
  }

  // Find existing conversation for this thread.
  let convo = await db.query.conversations.findFirst({
    where: and(
      eq(conversations.userId, link.userId),
      eq(conversations.channel, msg.channel),
      eq(conversations.channelThreadId, msg.externalThreadId),
      isNull(conversations.archivedAt),
    ),
    orderBy: (c, { desc: d }) => [d(c.updatedAt)],
  });

  if (!convo) {
    const [created] = await db
      .insert(conversations)
      .values({
        userId: link.userId,
        workspaceId,
        title: msg.body.slice(0, 50),
        channel: msg.channel,
        channelThreadId: msg.externalThreadId,
      })
      .returning();
    if (!created) throw new Error('Failed to create conversation');
    convo = created;
  }

  const task = await orchestrator.createTask(link.userId, workspaceId, msg.body, convo.id);

  const reply = await waitForTaskCompletion(task.id, link.userId, logger);

  try {
    await adapter.sendReply(msg.externalThreadId, reply);
  } catch (err) {
    logger.error({ err }, 'Failed to send channel reply');
  }
}

async function waitForTaskCompletion(
  taskId: string,
  userId: string,
  logger: { warn: Function },
): Promise<string> {
  const deadline = Date.now() + TASK_TIMEOUT_MS;
  while (Date.now() < deadline) {
    const t = await db.query.tasks.findFirst({
      where: and(eq(tasks.id, taskId), eq(tasks.userId, userId)),
    });
    if (!t) return 'Task kayboldu, tekrar dene.';
    if (t.status === 'completed') return t.output ?? '(boş yanıt)';
    if (t.status === 'failed') return `Hata: ${t.output ?? 'bilinmiyor'}`;
    if (t.status === 'cancelled') return 'Görev iptal edildi.';
    if (t.status === 'waiting_approval') {
      return 'Bu işlem onay bekliyor. Web arayüzünden onayla, sonra tekrar yaz.';
    }
    await new Promise((r) => setTimeout(r, POLL_INTERVAL_MS));
  }
  logger.warn({ taskId }, 'Task timed out waiting for channel reply');
  return 'Zaman aşımı oluştu — görev arka planda devam ediyor olabilir.';
}

export const __test__ = { POLL_INTERVAL_MS, TASK_TIMEOUT_MS };
