import type { ChannelAdapter, ChannelKind } from './types';

/**
 * Telegram bot adapter using the HTTP Bot API directly (no SDK).
 * Inbound messages arrive via webhook (POST /channels/telegram/webhook).
 * Outbound replies use sendMessage.
 *
 * Token comes from env: TELEGRAM_BOT_TOKEN.
 */
export class TelegramAdapter implements ChannelAdapter {
  readonly kind: ChannelKind = 'telegram';

  constructor(private token: string) {
    if (!token) throw new Error('TelegramAdapter requires a bot token');
  }

  async sendReply(chatId: string, body: string): Promise<void> {
    const url = `https://api.telegram.org/bot${this.token}/sendMessage`;
    const res = await fetch(url, {
      method: 'POST',
      headers: { 'content-type': 'application/json' },
      body: JSON.stringify({
        chat_id: chatId,
        // Telegram caps single message at 4096 chars
        text: body.length > 4000 ? body.slice(0, 3990) + '\n\n…(truncated)' : body,
        disable_web_page_preview: true,
      }),
    });
    if (!res.ok) {
      const text = await res.text().catch(() => '');
      throw new Error(`Telegram sendMessage failed: ${res.status} ${text.slice(0, 200)}`);
    }
  }

  /**
   * Returns the configured webhook URL, if a TELEGRAM_WEBHOOK_URL env is set.
   * Useful for the channels UI to display setup instructions.
   */
  static getWebhookUrl(): string | null {
    return process.env.TELEGRAM_WEBHOOK_URL ?? null;
  }

  static fromEnv(): TelegramAdapter | null {
    const token = process.env.TELEGRAM_BOT_TOKEN;
    if (!token) return null;
    return new TelegramAdapter(token);
  }
}

/**
 * ChannelAdapter contract.
 *
 * A channel adapter wraps an external messaging surface (Telegram, email,
 * Discord, SMS) and produces normalized IncomingMessage events. Replies go
 * out via `sendReply`. Routing from externalUserId -> repo userId is handled
 * by the router, not the adapter.
 */

export type ChannelKind = 'telegram' | 'email' | 'discord' | 'sms';

export interface IncomingMessage {
  channel: ChannelKind;
  /** External account id (Telegram chat id, email From, Discord user id, etc.) */
  externalUserId: string;
  /** External thread id (Telegram chat id, email Message-Id, etc.) — used to resume conversations */
  externalThreadId: string;
  body: string;
  /** Display name from the channel, used when creating a new channel link */
  externalDisplayName?: string;
  receivedAt: Date;
}

export interface ChannelAdapter {
  readonly kind: ChannelKind;
  /** Send a reply back to the same thread the message came from. */
  sendReply(externalThreadId: string, body: string): Promise<void>;
}

import { env } from '../env';

export interface InternalRequestOptions {
  userId: string;
  method?: 'GET' | 'POST' | 'PATCH' | 'PUT' | 'DELETE';
  path: string;
  query?: Record<string, string | number | boolean | undefined>;
  body?: unknown;
  signal?: AbortSignal;
  expectJson?: boolean;
}

export class ServiceHttpError extends Error {
  constructor(
    message: string,
    public status: number,
    public body: unknown,
  ) {
    super(message);
    this.name = 'ServiceHttpError';
  }
}

export async function internalRequest<T = unknown>(
  baseUrl: string,
  opts: InternalRequestOptions,
): Promise<T> {
  const url = new URL(opts.path, baseUrl);
  if (opts.query) {
    for (const [key, value] of Object.entries(opts.query)) {
      if (value === undefined) continue;
      url.searchParams.set(key, String(value));
    }
  }

  const headers: Record<string, string> = {
    Authorization: `Bearer ${env.INTERNAL_SERVICE_TOKEN}`,
    'X-User-Id': opts.userId,
  };
  let body: string | undefined;
  if (opts.body !== undefined) {
    headers['Content-Type'] = 'application/json';
    body = JSON.stringify(opts.body);
  }

  const response = await fetch(url, {
    method: opts.method ?? 'GET',
    headers,
    body,
    signal: opts.signal,
  });

  const expectJson = opts.expectJson ?? true;
  if (!response.ok) {
    let errorBody: unknown = null;
    try {
      errorBody = expectJson ? await response.json() : await response.text();
    } catch {
      errorBody = null;
    }
    throw new ServiceHttpError(
      `${opts.method ?? 'GET'} ${url.pathname} failed: ${response.status}`,
      response.status,
      errorBody,
    );
  }

  if (!expectJson) {
    return (await response.text()) as unknown as T;
  }
  if (response.status === 204) {
    return undefined as unknown as T;
  }
  return (await response.json()) as T;
}

