export class ListFilesTool implements Tool<{ path: string }, string> {
  name = 'list_files';
  description = 'List immediate children (files and directories) of a directory in the workspace.';
  requiresApproval = false;
  schema = z.object({
    path: z.string().describe('Directory path relative to workspace root, e.g. / or /src'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          path: { type: 'string', description: 'Directory path relative to workspace root' },
        },
        required: ['path'],
      },
    };
  }

  async execute(input: { path: string }, context: ToolContext): Promise<string> {
    try {
      const files = await context.clients.workspace.listFiles(
        context.userId,
        context.workspaceId,
        input.path,
      );
      if (files.length === 0) {
        return `(empty directory: ${input.path})`;
      }
      const lines = files.map((f) => {
        const marker = f.isDirectory ? 'd' : 'f';
        const size = f.isDirectory ? '-' : `${f.size}b`;
        return `${marker} ${size}\t${f.path}`;
      });
      return `Listing of ${input.path}:\n${lines.join('\n')}`;
    } catch (err: any) {
      const status = err?.status ?? 'unknown';
      return `Error listing ${input.path} (status=${status}): ${err?.message ?? String(err)}`;
    }
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';

export class SearchMemoryTool
  implements Tool<{ query: string; limit?: number; type?: string }, string>
{
  name = 'search_memory';
  description =
    "Search the user's long-term memory by semantic similarity. Returns the most relevant prior notes, facts, and task summaries.";
  requiresApproval = false;
  schema = z.object({
    query: z.string().min(1).describe('Natural-language query'),
    limit: z.number().int().min(1).max(20).optional().describe('Max results, default 5'),
    type: z.string().optional().describe('Filter by memory type (e.g. "fact", "preference")'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          query: { type: 'string', description: 'Natural-language query' },
          limit: { type: 'number', description: 'Max results, default 5' },
          type: { type: 'string', description: 'Filter by memory type' },
        },
        required: ['query'],
      },
    };
  }

  async execute(
    input: { query: string; limit?: number; type?: string },
    context: ToolContext,
  ): Promise<string> {
    try {
      const results = await context.clients.memory.search(context.userId, input.query, {
        limit: input.limit ?? 5,
        type: input.type,
        workspaceId: context.workspaceId,
      });
      if (results.length === 0) return `No memories matched: ${input.query}`;
      return results
        .map((r, i) => {
          const sim = typeof r.similarity === 'number' ? ` (sim=${r.similarity.toFixed(3)})` : '';
          return `${i + 1}. [${r.type}]${sim}\n   ${r.content}`;
        })
        .join('\n\n');
    } catch (err: any) {
      return `Memory search error: ${err?.message ?? String(err)}`;
    }
  }
}

