import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';
import { internalRequest } from '../clients/http';
import { env } from '../env';

const inputSchema = z.object({
  sql: z
    .string()
    .min(1)
    .max(20000)
    .describe('Read-only DuckDB SQL. The active dataset is referenced by its tableName.'),
  rowLimit: z.number().int().min(1).max(1000).optional(),
});

type Input = z.infer<typeof inputSchema>;

interface QueryResponse {
  columns: Array<{ name: string; type: string }>;
  rows: unknown[][];
  rowCount: number;
  truncated: boolean;
  durationMs: number;
}

const PREVIEW_ROWS = 20;

/**
 * Run a read-only SQL query against the user's DuckDB datasets via workspace-service.
 * Returns a compact text rendering capped at PREVIEW_ROWS rows so the LLM can reason
 * over results without overflowing the context window.
 */
export class QueryDatasetTool implements Tool<Input, string> {
  name = 'query_dataset';
  description =
    'Run a read-only SQL query against the user\'s registered datasets (DuckDB). ' +
    'Use list_datasets-style table names from the dataset catalog. INSERT/UPDATE/DELETE/DDL not allowed.';
  requiresApproval = false;
  schema = inputSchema;

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          sql: {
            type: 'string',
            description: 'Read-only DuckDB SQL referencing dataset tables by their tableName.',
          },
          rowLimit: {
            type: 'number',
            description: 'Optional row cap (default 1000, max 1000 visible to the agent).',
          },
        },
        required: ['sql'],
      },
    };
  }

  async execute(input: Input, context: ToolContext): Promise<string> {
    const limit = Math.min(input.rowLimit ?? 200, 1000);
    const result = await internalRequest<QueryResponse>(env.WORKSPACE_SERVICE_URL, {
      userId: context.userId,
      method: 'POST',
      path: '/api/datasets/query',
      body: { sql: input.sql, rowLimit: limit },
    });

    const head = result.rows.slice(0, PREVIEW_ROWS);
    const headerLine = result.columns.map((c) => c.name).join(' | ');
    const body = head
      .map((row) => row.map((v) => formatCell(v)).join(' | '))
      .join('\n');
    const more = result.rowCount > head.length ? `\n…(${result.rowCount - head.length} more rows)` : '';
    const truncatedNote = result.truncated ? '\n[server truncated to row cap]' : '';
    return `${headerLine}\n${body}${more}${truncatedNote}\n(${result.rowCount} rows, ${result.durationMs}ms)`;
  }
}

function formatCell(v: unknown): string {
  if (v === null || v === undefined) return 'NULL';
  if (typeof v === 'string') return v.length > 80 ? v.slice(0, 77) + '…' : v;
  if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'bigint') return String(v);
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';
import { env } from '../env';

interface SearchResult {
  title: string;
  url: string;
  snippet?: string;
}

async function searchBrave(query: string, limit: number, apiKey: string): Promise<SearchResult[]> {
  const url = new URL('https://api.search.brave.com/res/v1/web/search');
  url.searchParams.set('q', query);
  url.searchParams.set('count', String(Math.min(limit, 10)));
  const response = await fetch(url, {
    headers: {
      'X-Subscription-Token': apiKey,
      Accept: 'application/json',
    },
  });
  if (!response.ok) {
    throw new Error(`Brave search failed: ${response.status}`);
  }
  const data: any = await response.json();
  const items = data?.web?.results ?? [];
  return items.map((it: any) => ({
    title: String(it.title ?? ''),
    url: String(it.url ?? ''),
    snippet: typeof it.description === 'string' ? it.description : undefined,
  }));
}

async function searchTavily(query: string, limit: number, apiKey: string): Promise<SearchResult[]> {
  const response = await fetch('https://api.tavily.com/search', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ api_key: apiKey, query, max_results: Math.min(limit, 10) }),
  });
  if (!response.ok) {
    throw new Error(`Tavily search failed: ${response.status}`);
  }
  const data: any = await response.json();
  const items = Array.isArray(data?.results) ? data.results : [];
  return items.map((it: any) => ({
    title: String(it.title ?? ''),
    url: String(it.url ?? ''),
    snippet: typeof it.content === 'string' ? it.content : undefined,
  }));
}

async function searchSerpApi(
  query: string,
  limit: number,
  apiKey: string,
): Promise<SearchResult[]> {
  const url = new URL('https://serpapi.com/search.json');
  url.searchParams.set('q', query);
  url.searchParams.set('api_key', apiKey);
  url.searchParams.set('num', String(Math.min(limit, 10)));
  const response = await fetch(url);
  if (!response.ok) {
    throw new Error(`SerpAPI search failed: ${response.status}`);
  }
  const data: any = await response.json();
  const items = Array.isArray(data?.organic_results) ? data.organic_results : [];
  return items.map((it: any) => ({
    title: String(it.title ?? ''),
    url: String(it.link ?? ''),
    snippet: typeof it.snippet === 'string' ? it.snippet : undefined,
  }));
}

export class WebSearchTool implements Tool<{ query: string; limit?: number }, string> {
  name = 'web_search';
  description =
    'Search the public web and return a short list of titles, URLs and snippets. Configured via WEB_SEARCH_PROVIDER.';
  requiresApproval = false;
  schema = z.object({
    query: z.string().min(1).describe('Search query'),
    limit: z.number().int().min(1).max(10).optional().describe('Max results, default 5'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          query: { type: 'string', description: 'Search query' },
          limit: { type: 'number', description: 'Max results, default 5' },
        },
        required: ['query'],
      },
    };
  }

  async execute(
    input: { query: string; limit?: number },
    _context: ToolContext,
  ): Promise<string> {
    const provider = env.WEB_SEARCH_PROVIDER;
    if (provider === 'none') {
      return 'Web search is disabled (WEB_SEARCH_PROVIDER=none). Set WEB_SEARCH_PROVIDER and WEB_SEARCH_API_KEY to enable.';
    }
    const apiKey = env.WEB_SEARCH_API_KEY;
    if (!apiKey) {
      return `Web search misconfigured: provider=${provider} but WEB_SEARCH_API_KEY is not set.`;
    }
    const limit = input.limit ?? 5;
    try {
      let results: SearchResult[];
      if (provider === 'brave') results = await searchBrave(input.query, limit, apiKey);
      else if (provider === 'tavily') results = await searchTavily(input.query, limit, apiKey);
      else results = await searchSerpApi(input.query, limit, apiKey);

      if (results.length === 0) return `No results for: ${input.query}`;
      return results
        .map((r, i) => `${i + 1}. ${r.title}\n   ${r.url}${r.snippet ? `\n   ${r.snippet}` : ''}`)
        .join('\n\n');
    } catch (err: any) {
      return `Web search error: ${err?.message ?? String(err)}`;
    }
  }
}

import { z } from 'zod';
import { Tool, ToolContext } from './registry';
import { ToolDefinition } from '../llm/types';
import { env } from '../env';

const PRIVATE_HOSTS = [
  'localhost',
  '127.0.0.1',
  '::1',
  '0.0.0.0',
];

function isPrivateHost(hostname: string): boolean {
  if (PRIVATE_HOSTS.includes(hostname)) return true;
  // IPv4 private ranges
  if (/^10\./.test(hostname)) return true;
  if (/^192\.168\./.test(hostname)) return true;
  if (/^172\.(1[6-9]|2\d|3[0-1])\./.test(hostname)) return true;
  if (/^169\.254\./.test(hostname)) return true; // link-local
  if (/^fe80:/i.test(hostname)) return true;
  return false;
}

function stripHtml(html: string): string {
  return html
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

export class WebFetchTool implements Tool<{ url: string; mode?: 'text' | 'raw' }, string> {
  name = 'web_fetch';
  description =
    'Fetch a public HTTP(S) URL and return its body as text. HTML is stripped to readable text by default. Output capped to WEB_FETCH_MAX_BYTES.';
  requiresApproval = false;
  schema = z.object({
    url: z.string().url().describe('Absolute http(s) URL to fetch'),
    mode: z.enum(['text', 'raw']).optional().describe('text strips HTML; raw returns body as-is'),
  });

  getDefinition(): ToolDefinition {
    return {
      name: this.name,
      description: this.description,
      parameters: {
        type: 'object',
        properties: {
          url: { type: 'string', description: 'Absolute http(s) URL to fetch' },
          mode: { type: 'string', enum: ['text', 'raw'], description: 'text (default) strips HTML' },
        },
        required: ['url'],
      },
    };
  }

  async execute(
    input: { url: string; mode?: 'text' | 'raw' },
    _context: ToolContext,
  ): Promise<string> {
    let parsed: URL;
    try {
      parsed = new URL(input.url);
    } catch {
      return `Invalid URL: ${input.url}`;
    }
    if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
      return `Refusing to fetch non-http(s) URL: ${parsed.protocol}`;
    }
    if (isPrivateHost(parsed.hostname)) {
      return `Refusing to fetch private/internal host: ${parsed.hostname}`;
    }

    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 15_000);
      const response = await fetch(parsed, {
        method: 'GET',
        redirect: 'follow',
        signal: controller.signal,
        headers: { 'User-Agent': 'CloudMindOS-Agent/0.1 (+https://github.com)' },
      });
      clearTimeout(timeout);

      const status = response.status;
      const contentType = response.headers.get('content-type') ?? '';
      const text = await response.text();
      const max = env.WEB_FETCH_MAX_BYTES;
      const body =
        input.mode === 'raw' || !/text\/html/i.test(contentType) ? text : stripHtml(text);
      const truncated = body.length > max ? `${body.slice(0, max)}\n[truncated]` : body;
      return `status=${status} content-type=${contentType}\n\n${truncated}`;
    } catch (err: any) {
      return `Fetch error: ${err?.message ?? String(err)}`;
    }
  }
}

