import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import {
  addMemorySchema,
  searchMemorySchema,
  updateMemorySchema,
  memoryResponseSchema,
  sendApiError,
} from '@pcp/shared';
import { MemoryService } from './service';
import { z } from 'zod';
import { env } from './env';
import type { FastifyRequest } from 'fastify';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';

export async function setupMemoryRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const memoryService = new MemoryService(fastify.log);

  async function getAuthenticatedUserId(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  server.post(
    '/memory/entries',
    {
      schema: {
        body: addMemorySchema,
        response: {
          201: memoryResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { type, content, metadata, workspaceId } = request.body;
      const memory = await memoryService.addMemory(userId, type, content, metadata, workspaceId);
      
      return reply.code(201).send(memory);
    }
  );

  server.post(
    '/memory/search',
    {
      schema: {
        body: searchMemorySchema,
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { query, limit, type, workspaceId, minSimilarity } = request.body;
      const results = await memoryService.searchMemory(userId, query, {
        limit,
        type,
        workspaceId,
        minSimilarity,
      });

      return { results };
    }
  );

  server.patch(
    '/memory/entries/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateMemorySchema,
        response: {
          200: memoryResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const updated = await memoryService.updateMemory(request.params.id, userId, request.body);
      if (!updated) return sendApiError(reply, 404, 'NOT_FOUND', 'Memory not found');
      
      return updated;
    }
  );

  server.delete(
    '/memory/entries/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await memoryService.deleteMemory(request.params.id, userId);
      return { success: true };
    }
  );
}

import { db } from '@pcp/db/src/client';
import { memoryEntries, workspaces } from '@pcp/db/src/schema';
import {
  validateSessionUserId,
  verifyUserExists as verifySharedUserExists,
} from '@pcp/db/src/session';
import { eq, and, sql, isNull } from 'drizzle-orm';
import { EmbeddingProvider } from './embeddings/types';
import { OpenAIEmbeddingProvider } from './embeddings/openai';
import { LocalHashEmbeddingProvider } from './embeddings/local';
import { env } from './env';

type MemorySearchRow = {
  id: string;
  user_id: string;
  workspace_id: string | null;
  type: string;
  content: string;
  metadata: unknown;
  created_at: Date | string;
  updated_at: Date | string;
  similarity: number;
};

type SqlRowsResult<T> = {
  rows?: T[];
};

export class MemoryError extends Error {
  constructor(
    message: string,
    public statusCode = 400,
  ) {
    super(message);
    this.name = 'MemoryError';
  }
}

export class MemoryService {
  private embeddings: EmbeddingProvider;

  constructor(private logger: any) {
    const apiKey = env.OPENAI_API_KEY;
    const useRemote =
      apiKey && !apiKey.startsWith('dev-') && !apiKey.toLowerCase().includes('change_me');
    if (useRemote) {
      this.embeddings = new OpenAIEmbeddingProvider(apiKey);
      this.logger.info({ provider: 'openai' }, 'MemoryService initialized');
    } else {
      this.embeddings = new LocalHashEmbeddingProvider(1536);
      this.logger.warn(
        { provider: 'local-hash' },
        'MemoryService using local hash embeddings — set OPENAI_API_KEY for higher recall',
      );
    }
  }

  async validateUserFromCookie(sessionId: string): Promise<string | null> {
    return validateSessionUserId(sessionId);
  }

  async verifyUserExists(userId: string): Promise<string | null> {
    if (!userId) return null;
    return verifySharedUserExists(userId);
  }

  async addMemory(
    userId: string,
    type: string,
    content: string,
    metadata?: any,
    workspaceId?: string,
  ) {
    await this.assertWorkspaceOwned(userId, workspaceId);
    const embedding = await this.embeddings.generate(content);

    const [memory] = await db
      .insert(memoryEntries)
      .values({
        userId,
        workspaceId: workspaceId || null,
        type,
        content,
        embedding,
        metadata,
      })
      .returning();

    return memory;
  }

  async searchMemory(
    userId: string,
    query: string,
    options?: {
      limit?: number;
      type?: string;
      workspaceId?: string;
      minSimilarity?: number;
    },
  ) {
    await this.assertWorkspaceOwned(userId, options?.workspaceId);
    const queryEmbedding = await this.embeddings.generate(query);
    const limit = options?.limit ?? 5;
    const minSimilarity = options?.minSimilarity;

    // Formatting embedding vector array as string for raw SQL execution
    const embeddingStr = `[${queryEmbedding.join(',')}]`;

    // Tenant scoping: user_id filter is mandatory; type/workspace narrow further.
    const conditions = [sql`user_id = ${userId}`];
    if (options?.type) conditions.push(sql`type = ${options.type}`);
    if (options?.workspaceId) conditions.push(sql`workspace_id = ${options.workspaceId}`);
    const whereClause = sql.join(conditions, sql` AND `);

    // Ranking uses pgvector L2 distance (`<->`) so the HNSW index from
    // migration 0010 (`vector_l2_ops`) is used. Both embedding providers
    // emit L2-normalized vectors, so for unit-length a, b:
    //   ||a - b||^2 = 2 - 2 * cos(a, b)
    //   => cos(a, b) = 1 - ||a - b||^2 / 2
    // We expose that as `similarity` (range [-1, 1], higher is better).
    const results = await db.execute(sql`
      SELECT id, user_id, workspace_id, type, content, metadata, created_at, updated_at,
             1 - power(embedding <-> ${embeddingStr}::vector, 2) / 2 AS similarity
      FROM memory_entries
      WHERE ${whereClause}
      ORDER BY embedding <-> ${embeddingStr}::vector
      LIMIT ${limit}
    `);

    const typedResults = results as SqlRowsResult<MemorySearchRow> | MemorySearchRow[];
    const rows = Array.isArray(typedResults) ? typedResults : typedResults.rows ?? [];
    if (typeof minSimilarity === 'number') {
      return rows.filter(
        (row) => typeof row.similarity === 'number' && row.similarity >= minSimilarity,
      );
    }
    return rows;
  }

  private async assertWorkspaceOwned(userId: string, workspaceId?: string): Promise<void> {
    if (!workspaceId) return;
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });
    if (!workspace) throw new MemoryError('Workspace not found', 404);
  }

  async updateMemory(
    id: string,
    userId: string,
    updates: { content?: string; metadata?: any; type?: string },
  ) {
    const dataToUpdate: any = { updatedAt: new Date() };

    if (updates.content) {
      dataToUpdate.content = updates.content;
      dataToUpdate.embedding = await this.embeddings.generate(updates.content);
    }

    if (updates.metadata) {
      dataToUpdate.metadata = updates.metadata;
    }

    if (updates.type) {
      dataToUpdate.type = updates.type;
    }

    const [updated] = await db
      .update(memoryEntries)
      .set(dataToUpdate)
      .where(and(eq(memoryEntries.id, id), eq(memoryEntries.userId, userId)))
      .returning();

    return updated;
  }

  async deleteMemory(id: string, userId: string) {
    await db
      .delete(memoryEntries)
      .where(and(eq(memoryEntries.id, id), eq(memoryEntries.userId, userId)));
    return { success: true };
  }
}

export interface EmbeddingProvider {
  generate(input: string): Promise<number[]>;
  generateBatch(inputs: string[]): Promise<number[][]>;
  getDimensions(): number;
}

import OpenAI from 'openai';
import { EmbeddingProvider } from './types';

export class OpenAIEmbeddingProvider implements EmbeddingProvider {
  private client: OpenAI;
  private model: string;
  private dimensions: number;

  constructor(apiKey: string, model: string = 'text-embedding-3-small', dimensions: number = 1536) {
    this.client = new OpenAI({ apiKey });
    this.model = model;
    this.dimensions = dimensions;
  }

  async generate(input: string): Promise<number[]> {
    const response = await this.client.embeddings.create({
      model: this.model,
      input,
      dimensions: this.dimensions,
    });
    return response.data[0]?.embedding || [];
  }

  async generateBatch(inputs: string[]): Promise<number[][]> {
    const response = await this.client.embeddings.create({
      model: this.model,
      input: inputs,
      dimensions: this.dimensions,
    });
    return response.data.map(d => d.embedding);
  }

  getDimensions(): number {
    return this.dimensions;
  }
}

import { createHash } from 'crypto';
import { EmbeddingProvider } from './types';

/**
 * Deterministic, dependency-free embedding provider used as a fallback when
 * no remote embedding service (OpenAI, MiniMax, ...) is configured. Quality
 * is far below a real model, but it keeps the memory pipeline working in
 * local / offline environments without changing the schema dimension.
 */
export class LocalHashEmbeddingProvider implements EmbeddingProvider {
  constructor(private dimensions: number = 1536) {}

  async generate(input: string): Promise<number[]> {
    return this.embed(input);
  }

  async generateBatch(inputs: string[]): Promise<number[][]> {
    return inputs.map((i) => this.embed(i));
  }

  getDimensions(): number {
    return this.dimensions;
  }

  private embed(text: string): number[] {
    const tokens = text
      .toLowerCase()
      .replace(/[^a-z0-9\u00c0-\u024f\u4e00-\u9fff]+/gi, ' ')
      .split(/\s+/)
      .filter(Boolean);

    const vec = new Float64Array(this.dimensions);
    if (tokens.length === 0) return Array.from(vec);

    for (const token of tokens) {
      const hash = createHash('sha256').update(token).digest();
      // Distribute the 32-byte hash into the vector by repeating it across slots,
      // using signed values [-1, 1] for richer projection.
      for (let i = 0; i < this.dimensions; i++) {
        const byte = hash[i % hash.length] ?? 0;
        const signed = (byte - 127.5) / 127.5;
        vec[i] = (vec[i] ?? 0) + signed;
      }
    }

    // L2-normalize so cosine distance behaves correctly in pgvector.
    let norm = 0;
    for (let i = 0; i < this.dimensions; i++) norm += (vec[i] ?? 0) ** 2;
    norm = Math.sqrt(norm) || 1;
    const out = new Array<number>(this.dimensions);
    for (let i = 0; i < this.dimensions; i++) out[i] = (vec[i] ?? 0) / norm;
    return out;
  }
}

import { z } from 'zod';
import crypto from 'crypto';
import { isUnsafeEnvValue, resolveProductionValue } from '@pcp/shared';

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'test', 'production']).default('development'),
  PORT: z.coerce.number().int().positive().default(3006),
  DATABASE_URL: z.string().url().optional(),
  ENCRYPTION_KEY: z.string().optional(),
  PUBLISH_SECCOMP_PROFILE: z.string().optional(),
  PUBLISH_APPARMOR_PROFILE: z.string().optional(),
  PUBLISH_DOCKER_NETWORK: z.string().default('pcp-publish'),
});

const parsed = envSchema.parse(process.env);
const ctx = { isProduction: parsed.NODE_ENV === 'production' };

export const env = {
  NODE_ENV: parsed.NODE_ENV,
  PORT: parsed.PORT,
  DATABASE_URL: resolveProductionValue(ctx, 'DATABASE_URL', parsed.DATABASE_URL),
  ENCRYPTION_KEY: resolveEncryptionKey(parsed.ENCRYPTION_KEY),
  PUBLISH_SECCOMP_PROFILE: parsed.PUBLISH_SECCOMP_PROFILE,
  PUBLISH_APPARMOR_PROFILE: parsed.PUBLISH_APPARMOR_PROFILE,
  PUBLISH_DOCKER_NETWORK: parsed.PUBLISH_DOCKER_NETWORK,
};

function resolveEncryptionKey(value: string | undefined): string {
  const resolved = value?.trim() || '';
  if (resolved && resolved.length === 32) {
    if (ctx.isProduction && isUnsafeEnvValue(resolved)) {
      throw new Error('ENCRYPTION_KEY must be set to a non-default value in production');
    }
    return resolved;
  }
  if (ctx.isProduction) {
    throw new Error('ENCRYPTION_KEY must be exactly 32 characters in production');
  }
  console.warn(
    '[publish] WARNING: ENCRYPTION_KEY is not set to a valid 32-character value. ' +
      'Using an insecure deterministic development fallback key derived from a constant string. ' +
      'This must never be used with production or real data.',
  );
  // Deterministic dev key derived from a constant.
  // Never use this value outside development.
  return crypto.createHash('sha256').update('pcp-publish-dev-key').digest('hex').slice(0, 32);
}

import Fastify from 'fastify';
import cors from '@fastify/cors';
import rateLimit from '@fastify/rate-limit';
import cookie from '@fastify/cookie';
import { serializerCompiler, validatorCompiler } from 'fastify-type-provider-zod';
import {
  createApiErrorHandler,
