import { FastifyInstance, FastifyRequest } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { browserSessionSchema, navigateSchema, clickSchema, fillSchema, sendApiError } from '@pcp/shared';
import { BrowserService, type BrowserSessionInfo } from './service';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';
import { env } from './env';

const AUTH_BYPASS = env.AUTH_BYPASS;

function toJson(s: BrowserSessionInfo) {
  return {
    id: s.id,
    url: s.url,
    title: s.title,
    createdAt: s.createdAt instanceof Date ? s.createdAt.toISOString() : s.createdAt,
    lastUsedAt: s.lastUsedAt instanceof Date ? s.lastUsedAt.toISOString() : s.lastUsedAt,
  };
}

export async function setupBrowserRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const browserService = new BrowserService(fastify.log);

  async function authUser(request: FastifyRequest): Promise<string | null> {
    if (AUTH_BYPASS) return 'local-dev-user';
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  function handle(err: any, reply: any, fallback = 'Internal error') {
    const status = err?.statusCode ?? 500;
    if (status === 500) fastify.log.error({ err }, 'browser route failed');
    if (status === 401) {
      return sendApiError(reply, 401, 'UNAUTHORIZED', err?.message ?? fallback);
    }
    if (status === 403) {
      return sendApiError(reply, 403, 'FORBIDDEN', err?.message ?? fallback);
    }
    if (status === 404) {
      return sendApiError(reply, 404, 'NOT_FOUND', err?.message ?? fallback);
    }
    if (status === 409) {
      return sendApiError(reply, 409, 'CONFLICT', err?.message ?? fallback);
    }
    return sendApiError(reply, 500, 'INTERNAL_ERROR', err?.message ?? fallback);
  }

  server.get(
    '/browser/sessions',
    {
      schema: {
        response: { 200: z.object({ sessions: z.array(browserSessionSchema) }) },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      return { sessions: browserService.list(userId).map(toJson) };
    },
  );

  server.post(
    '/browser/sessions',
    { schema: { response: { 201: browserSessionSchema } } },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const s = await browserService.createSession(userId);
        return reply.code(201).send(toJson(s));
      } catch (err) {
        return handle(err, reply, 'Could not start session.');
      }
    },
  );

  server.delete(
    '/browser/sessions/:id',
    { schema: { params: z.object({ id: z.string().uuid() }) } },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await browserService.close(userId, request.params.id);
        return { success: true };
      } catch (err) {
        return handle(err, reply, 'Could not close session.');
      }
    },
  );

  server.post(
    '/browser/sessions/:id/navigate',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: navigateSchema,
        response: { 200: browserSessionSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const s = await browserService.navigate(userId, request.params.id, request.body.url);
        return toJson(s);
      } catch (err) {
        return handle(err, reply, 'Navigate failed.');
      }
    },
  );

  server.post(
    '/browser/sessions/:id/click',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: clickSchema,
        response: { 200: browserSessionSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const s = await browserService.click(userId, request.params.id, request.body.selector);
        return toJson(s);
      } catch (err) {
        return handle(err, reply, 'Click failed.');
      }
    },
  );

  server.post(
    '/browser/sessions/:id/fill',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: fillSchema,
        response: { 200: browserSessionSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        const s = await browserService.fill(
          userId,
          request.params.id,
          request.body.selector,
          request.body.value,
        );
        return toJson(s);
      } catch (err) {
        return handle(err, reply, 'Fill failed.');
      }
    },
  );

  server.get(
    '/browser/sessions/:id/screenshot',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        response: { 200: z.object({ pngBase64: z.string() }) },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await browserService.screenshot(userId, request.params.id);
      } catch (err) {
        return handle(err, reply, 'Screenshot failed.');
      }
    },
  );

  server.get(
    '/browser/sessions/:id/extract',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        response: {
          200: z.object({
            url: z.string(),
            title: z.string(),
            text: z.string(),
            links: z.array(z.object({ href: z.string(), text: z.string() })),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await browserService.extract(userId, request.params.id);
      } catch (err) {
        return handle(err, reply, 'Extract failed.');
      }
    },
  );
}

import { promises as fs } from 'node:fs';
import * as path from 'node:path';
import { randomUUID } from 'node:crypto';
import { lookup } from 'node:dns/promises';
import { isIP } from 'node:net';
import { env } from './env';

/**
 * In-memory pool of Playwright browser contexts. Playwright is lazy-loaded via an
 * indirect dynamic import so the service builds and the routes report a 503 when
 * the optional native dependency hasn't been installed.
 */

export interface BrowserSessionInfo {
  id: string;
  userId: string;
  url: string;
  title: string;
  createdAt: Date;
  lastUsedAt: Date;
}

interface InternalSession extends BrowserSessionInfo {
  context: any;
  page: any;
  timer?: NodeJS.Timeout;
}

let driverModule: any | null = null;
let driverError: string | null = null;

async function loadPlaywright(): Promise<any> {
  if (driverModule) return driverModule;
  try {
    const specifier = 'playwright';
    const mod = await (Function('s', 'return import(s)') as (s: string) => Promise<any>)(specifier);
    driverModule = mod;
    return mod;
  } catch (err) {
    driverError = `Playwright is not installed. Run "pnpm --filter @pcp/browser-service add playwright && pnpm --filter @pcp/browser-service exec playwright install chromium". Original error: ${(err as Error).message}`;
    throw new Error(driverError);
  }
}

export class BrowserService {
  private sessions = new Map<string, InternalSession>();

  constructor(
    private logger?: { info: (...a: any[]) => void; warn: (...a: any[]) => void; error: (...a: any[]) => void },
  ) {}

  list(userId: string): BrowserSessionInfo[] {
    return Array.from(this.sessions.values())
      .filter((s) => s.userId === userId)
      .map(toInfo);
  }

  async createSession(userId: string): Promise<BrowserSessionInfo> {
    const userSessions = Array.from(this.sessions.values()).filter((s) => s.userId === userId);
    if (userSessions.length >= env.BROWSER_MAX_SESSIONS_PER_USER) {
      throw httpErr(429, `Session limit reached (${env.BROWSER_MAX_SESSIONS_PER_USER}). Close one first.`);
    }
    const pw = await loadPlaywright();
    const profileDir = path.resolve(env.BROWSER_PROFILE_DIR, userId);
    await fs.mkdir(profileDir, { recursive: true });

    // launchPersistentContext gives us cookie/login persistence per user.
    const context = await pw.chromium.launchPersistentContext(profileDir, {
      headless: true,
      viewport: { width: 1280, height: 800 },
      acceptDownloads: false,
    });
    await context.route('**/*', async (route: any) => {
      const requestUrl = route.request().url();
      if (await isSafeNavigationUrl(requestUrl)) return route.continue();
      return route.abort('blockedbyclient');
    });
    const page = (await context.pages())[0] ?? (await context.newPage());

    const id = randomUUID();
    const session: InternalSession = {
      id,
      userId,
      url: 'about:blank',
      title: '',
      createdAt: new Date(),
      lastUsedAt: new Date(),
      context,
      page,
    };
    this.armIdleTimer(session);
    this.sessions.set(id, session);
    return toInfo(session);
  }

  async navigate(userId: string, sessionId: string, url: string): Promise<BrowserSessionInfo> {
    const s = this.requireSession(userId, sessionId);
    if (!(await isSafeNavigationUrl(url))) {
      throw httpErr(400, 'URL must be http(s) and not point at a private network.');
    }
    await s.page.goto(url, { waitUntil: 'domcontentloaded', timeout: 30000 });
    s.url = s.page.url();
    s.title = await s.page.title().catch(() => '');
    this.touch(s);
    return toInfo(s);
  }

  async click(userId: string, sessionId: string, selector: string): Promise<BrowserSessionInfo> {
    const s = this.requireSession(userId, sessionId);
    await s.page.click(selector, { timeout: 10000 });
    await s.page.waitForLoadState('domcontentloaded', { timeout: 10000 }).catch(() => {});
    s.url = s.page.url();
    s.title = await s.page.title().catch(() => '');
    this.touch(s);
    return toInfo(s);
  }

  async fill(
    userId: string,
    sessionId: string,
    selector: string,
    value: string,
  ): Promise<BrowserSessionInfo> {
    const s = this.requireSession(userId, sessionId);
    await s.page.fill(selector, value, { timeout: 10000 });
    this.touch(s);
    return toInfo(s);
  }

  async screenshot(userId: string, sessionId: string): Promise<{ pngBase64: string }> {
    const s = this.requireSession(userId, sessionId);
    const buf = await s.page.screenshot({ type: 'png', fullPage: false });
    this.touch(s);
    return { pngBase64: Buffer.from(buf).toString('base64') };
  }

  /** Extract trimmed visible text + a small set of links for LLM consumption. */
  async extract(userId: string, sessionId: string): Promise<{
    url: string;
    title: string;
    text: string;
    links: Array<{ href: string; text: string }>;
  }> {
    const s = this.requireSession(userId, sessionId);
    const result = await s.page.evaluate(() => {
      type LinkLike = { href?: string; innerText?: string };
      type BrowserDocLike = {
        body?: { innerText?: string };
        querySelectorAll: (selector: string) => ArrayLike<LinkLike>;
      };
      const doc = (globalThis as { document?: BrowserDocLike }).document;
      const text = String(doc?.body?.innerText ?? '').trim();
      const anchors = doc ? Array.from(doc.querySelectorAll('a[href]')) : [];
      const links = anchors
        .slice(0, 100)
        .map((a) => ({
          href: String(a.href ?? ''),
          text: String(a.innerText ?? '').trim().slice(0, 200),
        }))
        .filter((l: { href: string; text: string }) => l.href && l.text);
      return { text, links };
    });
    this.touch(s);
    return {
      url: s.page.url(),
      title: await s.page.title().catch(() => ''),
      text: result.text.length > 8000 ? result.text.slice(0, 8000) + '\n…(truncated)' : result.text,
      links: result.links,
    };
  }

  async close(userId: string, sessionId: string): Promise<void> {
    const s = this.requireSession(userId, sessionId);
    await this.disposeSession(s);
  }

  async closeAll(userId: string): Promise<number> {
    const mine = Array.from(this.sessions.values()).filter((s) => s.userId === userId);
    for (const s of mine) await this.disposeSession(s);
    return mine.length;
  }

  private requireSession(userId: string, id: string): InternalSession {
    const s = this.sessions.get(id);
    if (!s || s.userId !== userId) throw httpErr(404, 'Session not found');
    return s;
  }

  private touch(s: InternalSession) {
    s.lastUsedAt = new Date();
    this.armIdleTimer(s);
  }

  private armIdleTimer(s: InternalSession) {
    if (s.timer) clearTimeout(s.timer);
    s.timer = setTimeout(() => {
      this.disposeSession(s).catch((err) =>
        this.logger?.warn?.({ err, sessionId: s.id }, 'idle session disposal failed'),
      );
    }, env.BROWSER_SESSION_TIMEOUT_MS);
  }

  private async disposeSession(s: InternalSession) {
    if (s.timer) clearTimeout(s.timer);
    this.sessions.delete(s.id);
    try {
      await s.context.close();
    } catch (err) {
      this.logger?.warn?.({ err, sessionId: s.id }, 'context close failed');
    }
  }
}

function toInfo(s: InternalSession): BrowserSessionInfo {
  return {
    id: s.id,
    userId: s.userId,
    url: s.url,
    title: s.title,
    createdAt: s.createdAt,
    lastUsedAt: s.lastUsedAt,
  };
}

function httpErr(statusCode: number, message: string) {
  return Object.assign(new Error(message), { statusCode });
}

/** Reject non-http(s) URLs and obvious private-network targets to limit SSRF surface. */
export function isSafeUrl(url: string): boolean {
  let u: URL;
  try {
    u = new URL(url);
  } catch {
    return false;
  }
  if (u.protocol !== 'http:' && u.protocol !== 'https:') return false;
  let host = u.hostname.toLowerCase();
  if (host.startsWith('[') && host.endsWith(']')) host = host.slice(1, -1);
  if (
    host === 'localhost' ||
    host === '0.0.0.0' ||
    host.endsWith('.localhost') ||
    host.endsWith('.local')
  ) {
    return false;
  }
  if (isPrivateAddress(host)) return false;
  return true;
}

export async function isSafeNavigationUrl(url: string): Promise<boolean> {
  if (!isSafeUrl(url)) return false;

  const { hostname } = new URL(url);
  let host = hostname.toLowerCase();
  if (host.startsWith('[') && host.endsWith(']')) host = host.slice(1, -1);
  if (isIP(host)) return true;

  try {
    const addresses = await lookup(host, { all: true, verbatim: true });
    return addresses.length > 0 && addresses.every(({ address }) => !isPrivateAddress(address));
  } catch {
    return false;
  }
}

function isPrivateAddress(host: string): boolean {
  const normalized = host.toLowerCase();
  const ipv4 = parseIpv4(normalized);
  if (ipv4) {
    const [a, b] = ipv4;
    if (a === 0 || a === 10 || a === 127) return true;
    if (a === 100 && b >= 64 && b <= 127) return true;
    if (a === 169 && b === 254) return true;
    if (a === 172 && b >= 16 && b <= 31) return true;
    if (a === 192 && b === 168) return true;
    if (a >= 224) return true;
    return false;
  }

  const ipv6 = normalized.startsWith('::ffff:') ? normalized.slice(7) : normalized;
  const mappedIpv4 = parseIpv4(ipv6) ?? parseIpv4MappedHex(ipv6);
  if (mappedIpv4) return isPrivateAddress(mappedIpv4.join('.'));

  return (
    normalized === '::1' ||
    normalized === '::' ||
    normalized.startsWith('fe80:') ||
    normalized.startsWith('fc') ||
    normalized.startsWith('fd')
  );
}

function parseIpv4MappedHex(host: string): [number, number, number, number] | null {
  const match = /^([0-9a-f]{1,4}):([0-9a-f]{1,4})$/i.exec(host);
  if (!match) return null;
  const high = Number.parseInt(match[1] ?? '', 16);
  const low = Number.parseInt(match[2] ?? '', 16);
  if (!Number.isInteger(high) || !Number.isInteger(low) || high > 0xffff || low > 0xffff) {
    return null;
  }
  return [high >> 8, high & 0xff, low >> 8, low & 0xff];
}

function parseIpv4(host: string): [number, number, number, number] | null {
  const parts = host.split('.');
  if (parts.length !== 4) return null;
  const octets = parts.map((part) => Number(part));
  if (octets.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) return null;
  const [a, b, c, d] = octets;
  if (a === undefined || b === undefined || c === undefined || d === undefined) return null;
  return [a, b, c, d];
}

