'use client';

import { useMemo, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  ExternalLink,
  Globe2,
  Play,
  RefreshCw,
  Rocket,
  Server,
  Square,
  Trash2,
} from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { StatusBadge } from '@/components/ui/status-badge';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import { WorkspaceSummary } from '@/components/workspace/create-workspace-dialog';
import {publishApi, workspaceApi , toastApiError} from '@/lib/api';
import { formatDate } from '@/lib/format';
import { useUser } from '@/lib/auth';

type WorkspacesResponse = {
  workspaces: WorkspaceSummary[];
  page: number;
  limit: number;
};

type HostedService = {
  id: string;
  workspaceId: string;
  name: string;
  slug: string;
  status: string;
  kind: string;
  updatedAt: string;
  publicUrl?: string | null;
  autoRestart?: boolean;
  crashCount?: number;
  lastHealthAt?: string | null;
  lastHealthOk?: boolean | null;
};

export default function HostingPage() {
  const { data: user } = useUser();
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [name, setName] = useState('');
  const [slug, setSlug] = useState('');
  const [kind, setKind] = useState('static');
  const [rootPath, setRootPath] = useState('/');
  const [workspaceId, setWorkspaceId] = useState('');
  const [deleteTarget, setDeleteTarget] = useState<string | null>(null);

  const workspacesQuery = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaces = useMemo(
    () => workspacesQuery.data?.workspaces ?? [],
    [workspacesQuery.data],
  );
  const defaultWorkspaceId = workspaceId || workspaces[0]?.id || '';

  const servicesQuery = useQuery({
    queryKey: ['hosted-services', defaultWorkspaceId],
    enabled: Boolean(user?.id && defaultWorkspaceId),
    retry: false,
    refetchInterval: 20_000,
    queryFn: async () => {
      const res = await publishApi.get('/hosted-services', {
        params: { workspaceId: defaultWorkspaceId },
      });
      return res.data as HostedService[];
    },
  });

  const services = servicesQuery.data ?? [];
  const hostingReady = Boolean(user?.id && !servicesQuery.isError);

  const workspaceNameById = useMemo(() => {
    return new Map(workspaces.map((w) => [w.id, w.name]));
  }, [workspaces]);

  const createService = useMutation({
    mutationFn: async () => {
      if (!user?.id) throw new Error('You must be signed in.');
      await publishApi.post('/hosted-services', {
        workspaceId: defaultWorkspaceId,
        name: name.trim(),
        slug: normalizeSlug(slug || name),
        kind,
        rootPath,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service created.');
      setShowCreate(false);
      setName('');
      setSlug('');
      setKind('static');
      setRootPath('/');
    },
    onError: (e) => toastApiError(e, 'Could not create service.'),
  });

  const startService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/start`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service starting...');
    },
    onError: (e) => toastApiError(e, 'Could not start service.'),
  });

  const stopService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/stop`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service stopped.');
    },
    onError: (e) => toastApiError(e, 'Could not stop service.'),
  });

  const restartService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/restart`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service restarting...');
    },
    onError: (e) => toastApiError(e, 'Could not restart service.'),
  });

  const updateAutoRestart = useMutation({
    mutationFn: async ({ id, autoRestart }: { id: string; autoRestart: boolean }) => {
      await publishApi.patch(`/hosted-services/${id}`, { autoRestart });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
    },
    onError: (e) => toastApiError(e, 'Could not update service.'),
  });

  const deleteService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.delete(`/hosted-services/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service deleted.');
      setDeleteTarget(null);
    },
    onError: (e) => toastApiError(e, 'Could not delete service.'),
  });

  const canCreate = hostingReady && Boolean(defaultWorkspaceId && name.trim());

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Hosting</h2>
          <p className="text-sm text-muted-foreground">Deploy workspace apps as hosted services</p>
        </div>
        <Button
          size="sm"
          onClick={() => setShowCreate((v) => !v)}
          disabled={!hostingReady || workspaces.length === 0}
        >
          <Rocket className="mr-1.5 h-3.5 w-3.5" />
          Create service
        </Button>
      </div>

      {servicesQuery.isError && (
        <div className="mt-4 rounded-lg border border-amber-500/30 bg-amber-500/5 p-3 text-sm text-amber-600 dark:text-amber-400">
          Publish service is not available. Hosting actions are disabled until it responds.
        </div>
      )}

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (canCreate) createService.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-2 lg:grid-cols-3"
        >
          <div className="space-y-1.5">
            <Label htmlFor="svc-name">Service name</Label>
            <Input
              id="svc-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My App"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-slug">Slug (subdomain)</Label>
            <Input
              id="svc-slug"
              value={slug}
              onChange={(e) => setSlug(e.target.value)}
              placeholder={normalizeSlug(name || 'my-app')}
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-kind">Kind</Label>
            <select
              id="svc-kind"
              value={kind}
              onChange={(e) => setKind(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              <option value="static">Static (HTML/CSS/JS)</option>
              <option value="vite">Vite App</option>
              <option value="node">Node.js API</option>
            </select>
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-root">Root path</Label>
            <Input
              id="svc-root"
              value={rootPath}
              onChange={(e) => setRootPath(e.target.value)}
              placeholder="/"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-workspace">Workspace</Label>
            <select
              id="svc-workspace"
              value={defaultWorkspaceId}
              onChange={(e) => setWorkspaceId(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              {workspaces.map((w) => (
                <option key={w.id} value={w.id}>
                  {w.name}
                </option>
              ))}
            </select>
          </div>
          <div className="flex items-end">
            <Button type="submit" size="sm" disabled={!canCreate || createService.isPending}>
              {createService.isPending ? 'Creating...' : 'Create'}
            </Button>
          </div>
        </form>
      )}

      <div className="mt-6">
        {servicesQuery.isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : services.length > 0 ? (
          <div className="space-y-3">
            {services.map((svc) => {
              const isRunning = svc.status === 'running';
              const isStarting = svc.status === 'starting';
              return (
                <div
                  key={svc.id}
                  className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
                >
                  <div className="flex min-w-0 items-center gap-3">
                    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                      <Server className="h-5 w-5 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium text-foreground">{svc.name}</h3>
                        <StatusBadge
                          variant={isRunning ? 'running' : isStarting ? 'pending' : 'stopped'}
                          dot
                        >
                          {svc.status}
                        </StatusBadge>
                        <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
                          {svc.kind}
                        </span>
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {svc.slug}.apps.localhost ·{' '}
                        {workspaceNameById.get(svc.workspaceId) || 'Workspace'} ·{' '}
                        {formatDate(svc.updatedAt)}
                      </p>
                      <div className="mt-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[11px] text-muted-foreground">
                        <span
                          className={
                            svc.lastHealthOk === false
                              ? 'text-destructive'
                              : svc.lastHealthOk
                                ? 'text-emerald-600 dark:text-emerald-400'
                                : ''
                          }
                          title={svc.lastHealthAt ?? undefined}
                        >
                          Health:{' '}
                          {svc.lastHealthOk === null || svc.lastHealthOk === undefined
                            ? '—'
                            : svc.lastHealthOk
                              ? 'OK'
                              : 'failing'}
                        </span>
                        <span>Crashes: {svc.crashCount ?? 0}</span>
                        <label className="flex cursor-pointer items-center gap-1">
                          <input
                            type="checkbox"
                            checked={svc.autoRestart ?? true}
                            onChange={(e) =>
                              updateAutoRestart.mutate({
                                id: svc.id,
                                autoRestart: e.target.checked,
                              })
                            }
                            className="h-3 w-3"
                          />
                          Auto-restart
                        </label>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {isRunning ? (
                      <>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => restartService.mutate(svc.id)}
                          disabled={restartService.isPending}
                          title="Restart"
                        >
                          <RefreshCw className="mr-1 h-3.5 w-3.5" /> Restart
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => stopService.mutate(svc.id)}
                          disabled={stopService.isPending}
                        >
                          <Square className="mr-1 h-3.5 w-3.5" /> Stop
                        </Button>
                      </>
                    ) : (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => startService.mutate(svc.id)}
                        disabled={startService.isPending || isStarting}
                      >
                        <Play className="mr-1 h-3.5 w-3.5" /> Start
                      </Button>
                    )}
                    {svc.publicUrl && (
                      <a href={svc.publicUrl} target="_blank" rel="noreferrer">
                        <Button size="sm" variant="outline">
                          Open <ExternalLink className="ml-1 h-3.5 w-3.5" />
                        </Button>
                      </a>
                    )}
                    <Button
                      size="sm"
                      variant="ghost"
                      className="text-destructive hover:text-destructive"
                      onClick={() => setDeleteTarget(svc.id)}
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <EmptyState
            icon={<Globe2 className="h-6 w-6" />}
            title="No services yet"
            description="Create a static site, Vite app, or Node.js service from an existing workspace."
            action={{
              label: 'Create service',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={() => setDeleteTarget(null)}
        title="Delete service"
        description="This will stop the running container and remove the service. This action cannot be undone."
        confirmLabel="Delete"
        variant="destructive"
        onConfirm={async () => {
          if (deleteTarget) await deleteService.mutateAsync(deleteTarget);
        }}
      />
    </div>
  );
}

function normalizeSlug(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

'use client';

import { useMemo, useRef, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Database, Upload, Trash2, Play, Eye, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import axios from 'axios';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { workspaceApi, apiEndpoints, toastApiError} from '@/lib/api';

type Dataset = {
  id: string;
  name: string;
  tableName: string;
  sourceType: string;
  sourceFilename: string | null;
  columns: Array<{ name: string; type: string }>;
  rowCount: number;
  sizeBytes: number;
  createdAt: string;
};

type QueryResult = {
  columns: Array<{ name: string; type: string }>;
  rows: unknown[][];
  rowCount: number;
  truncated: boolean;
  durationMs: number;
};

const ACCEPT = '.csv,.tsv,.json,.ndjson,.jsonl,.parquet';

export default function DatasetsPage() {
  const qc = useQueryClient();
  const fileRef = useRef<HTMLInputElement>(null);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [sql, setSql] = useState('');
  const [result, setResult] = useState<QueryResult | null>(null);

  const { data, isLoading } = useQuery({
    queryKey: ['datasets'],
    queryFn: async () => {
      const res = await workspaceApi.get('/datasets');
      return (res.data?.datasets ?? []) as Dataset[];
    },
    retry: false,
  });
  const datasets = useMemo(() => data ?? [], [data]);
  const active = useMemo(
    () => datasets.find((d) => d.id === activeId) ?? null,
    [datasets, activeId],
  );

  const importMut = useMutation({
    mutationFn: async (file: File) => {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('name', file.name.replace(/\.[^.]+$/, ''));
      const res = await axios.post(`${apiEndpoints.workspace}/datasets/import`, fd, {
        withCredentials: true,
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      return res.data as Dataset;
    },
    onSuccess: (ds) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      setActiveId(ds.id);
      setSql(`SELECT * FROM "${ds.tableName}" LIMIT 100`);
      toast.success(
        `Imported ${ds.rowCount.toLocaleString()} rows from ${ds.sourceFilename ?? ds.name}.`,
      );
    },
    onError: (e) => toastApiError(e, 'Import failed.'),
  });

  const removeMut = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.delete(`/datasets/${id}`);
    },
    onSuccess: (_, id) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      if (activeId === id) {
        setActiveId(null);
        setResult(null);
      }
      toast.success('Dataset removed.');
    },
    onError: (e) => toastApiError(e, 'Could not remove dataset.'),
  });

  const queryMut = useMutation({
    mutationFn: async (q: string) => {
      const res = await workspaceApi.post(`/datasets/query`, { sql: q, rowLimit: 500 });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Query failed.'),
  });

  const previewMut = useMutation({
    mutationFn: async (id: string) => {
      const res = await workspaceApi.get(`/datasets/${id}/preview`, { params: { limit: 50 } });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Preview failed.'),
  });

  const onPickFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    importMut.mutate(f);
    e.target.value = '';
  };

  return (
    <div className="mx-auto flex max-w-6xl flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Database className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Datasets</h2>
          <p className="text-sm text-muted-foreground">
            Upload CSV, JSON, or Parquet files into your private DuckDB and query them with SQL.
          </p>
        </div>
        <input ref={fileRef} type="file" accept={ACCEPT} onChange={onPickFile} className="hidden" />
        <Button onClick={() => fileRef.current?.click()} disabled={importMut.isPending}>
          {importMut.isPending ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Upload className="mr-1.5 h-3.5 w-3.5" />
          )}
          {importMut.isPending ? 'Importing...' : 'Import file'}
        </Button>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-[260px_1fr]">
        <aside className="rounded-xl border border-border bg-card p-3">
          <h3 className="mb-2 px-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Catalog
          </h3>
          {isLoading ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">Loading...</p>
          ) : datasets.length === 0 ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">
              No datasets yet. Import a file to get started.
            </p>
          ) : (
            <ul className="space-y-1">
              {datasets.map((d) => (
                <li key={d.id}>
                  <button
                    type="button"
                    onClick={() => {
                      setActiveId(d.id);
                      setSql(`SELECT * FROM "${d.tableName}" LIMIT 100`);
                    }}
                    className={`group flex w-full items-start justify-between gap-2 rounded-lg px-2 py-2 text-left text-sm transition-colors hover:bg-muted ${
                      activeId === d.id ? 'bg-muted' : ''
                    }`}
                  >
                    <div className="min-w-0 flex-1">
                      <div className="truncate font-medium text-foreground">{d.name}</div>
                      <div className="truncate text-[11px] text-muted-foreground">
                        {d.tableName} · {d.rowCount.toLocaleString()} rows · {d.columns.length} cols
                      </div>
                    </div>
                    <span
                      role="button"
                      tabIndex={0}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                        }
                      }}
                      className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <main className="space-y-4">
          {active ? (
            <div className="rounded-xl border border-border bg-card p-4">
              <div className="mb-3 flex flex-wrap items-center gap-2">
                <h3 className="font-medium text-foreground">{active.name}</h3>
                <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono uppercase text-muted-foreground">
                  {active.sourceType}
                </span>
                <span className="text-xs text-muted-foreground">
                  table <code className="font-mono">{active.tableName}</code>
                </span>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => previewMut.mutate(active.id)}
                  disabled={previewMut.isPending}
                  className="ml-auto"
                >
                  <Eye className="mr-1.5 h-3.5 w-3.5" />
                  Preview
                </Button>
              </div>

              <div className="mb-2">
                <Label className="text-xs text-muted-foreground">SQL</Label>
                <textarea
                  value={sql}
                  onChange={(e) => setSql(e.target.value)}
                  rows={5}
                  className="mt-1 w-full rounded-md border border-input bg-background px-3 py-2 font-mono text-xs text-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                  placeholder={`SELECT * FROM "${active.tableName}" LIMIT 100`}
                />
              </div>
              <div className="flex justify-end">
                <Button
                  size="sm"
                  onClick={() => sql.trim() && queryMut.mutate(sql)}
                  disabled={!sql.trim() || queryMut.isPending}
                >
                  {queryMut.isPending ? (
                    <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
                  ) : (
                    <Play className="mr-1.5 h-3.5 w-3.5" />
                  )}
                  Run
                </Button>
              </div>
            </div>
          ) : (
            <div className="rounded-xl border border-dashed border-border p-10 text-center text-sm text-muted-foreground">
              Select a dataset on the left or import a new file.
            </div>
          )}

          {result && (
            <div className="rounded-xl border border-border bg-card p-3">
              <div className="mb-2 flex items-center justify-between text-xs text-muted-foreground">
                <span>
                  {result.rowCount} rows · {result.durationMs}ms
                  {result.truncated && ' · truncated'}
                </span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="border-b border-border">
                      {result.columns.map((c) => (
                        <th
                          key={c.name}
                          className="whitespace-nowrap px-2 py-1.5 text-left font-medium text-foreground"
                        >
                          {c.name}
                          <span className="ml-1 text-[10px] font-normal text-muted-foreground">
                            {c.type}
                          </span>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {result.rows.map((row, i) => (
                      <tr key={i} className="border-b border-border/50 last:border-0">
                        {row.map((cell, j) => (
                          <td
                            key={j}
                            className="max-w-[280px] truncate whitespace-nowrap px-2 py-1 font-mono text-muted-foreground"
                          >
                            {formatCell(cell)}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

function formatCell(v: unknown): string {
  if (v === null || v === undefined) return '—';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'bigint') return String(v);
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Globe, Plus, Trash2, ImageDown, FileText, Loader2, ArrowRight } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { browserApi, toastApiError} from '@/lib/api';

type Session = {
  id: string;
  url: string;
  title: string;
  createdAt: string;
  lastUsedAt: string;
};

type ExtractResult = {
  url: string;
  title: string;
  text: string;
  links: Array<{ href: string; text: string }>;
};

export default function BrowserPage() {
  const qc = useQueryClient();
  const [activeId, setActiveId] = useState<string | null>(null);
  const [navUrl, setNavUrl] = useState('https://example.com');
  const [extract, setExtract] = useState<ExtractResult | null>(null);
  const [shotSrc, setShotSrc] = useState<string | null>(null);

  const { data, isLoading } = useQuery({
    queryKey: ['browser-sessions'],
    queryFn: async () => {
      const res = await browserApi.get('/browser/sessions');
      return (res.data?.sessions ?? []) as Session[];
    },
    retry: false,
  });
  const sessions = data ?? [];

  const create = useMutation({
    mutationFn: async () => {
      const res = await browserApi.post('/browser/sessions');
      return res.data as Session;
    },
    onSuccess: (s) => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
      setActiveId(s.id);
      toast.success('Session started.');
    },
    onError: (e) => toastApiError(e, 'Could not start session.'),
  });

  const close = useMutation({
    mutationFn: async (id: string) => {
      await browserApi.delete(`/browser/sessions/${id}`);
    },
    onSuccess: (_, id) => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
      if (activeId === id) {
        setActiveId(null);
        setExtract(null);
        setShotSrc(null);
      }
    },
    onError: (e) => toastApiError(e, 'Could not close session.'),
  });

  const navigate = useMutation({
    mutationFn: async ({ id, url }: { id: string; url: string }) => {
      const res = await browserApi.post(`/browser/sessions/${id}/navigate`, { url });
      return res.data as Session;
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['browser-sessions'] });
    },
    onError: (e) => toastApiError(e, 'Navigate failed.'),
  });

  const doExtract = useMutation({
    mutationFn: async (id: string) => {
      const res = await browserApi.get(`/browser/sessions/${id}/extract`);
      return res.data as ExtractResult;
    },
    onSuccess: (r) => setExtract(r),
    onError: (e) => toastApiError(e, 'Extract failed.'),
  });

  const doShot = useMutation({
    mutationFn: async (id: string) => {
      const res = await browserApi.get(`/browser/sessions/${id}/screenshot`);
      return (res.data as { pngBase64: string }).pngBase64;
    },
    onSuccess: (b64) => setShotSrc(`data:image/png;base64,${b64}`),
    onError: (e) => toastApiError(e, 'Screenshot failed.'),
  });

  return (
    <div className="mx-auto flex max-w-6xl flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Globe className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Cloud Browser</h2>
          <p className="text-sm text-muted-foreground">
            Headless Playwright sessions with persistent per-user profiles. Navigate, extract page
            content, or take screenshots.
          </p>
        </div>
        <Button onClick={() => create.mutate()} disabled={create.isPending}>
          {create.isPending ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Plus className="mr-1.5 h-3.5 w-3.5" />
          )}
          New session
        </Button>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-[260px_1fr]">
        <aside className="rounded-xl border border-border bg-card p-3">
          <h3 className="mb-2 px-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Sessions
          </h3>
          {isLoading ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">Loading...</p>
          ) : sessions.length === 0 ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">
              No active sessions. Start one to begin.
            </p>
          ) : (
            <ul className="space-y-1">
              {sessions.map((s) => (
                <li key={s.id}>
                  <button
                    type="button"
                    onClick={() => {
                      setActiveId(s.id);
                      setNavUrl(s.url === 'about:blank' ? 'https://example.com' : s.url);
                      setExtract(null);
                      setShotSrc(null);
                    }}
                    className={`group flex w-full items-start justify-between gap-2 rounded-lg px-2 py-2 text-left text-sm transition-colors hover:bg-muted ${
                      activeId === s.id ? 'bg-muted' : ''
                    }`}
                  >
                    <div className="min-w-0 flex-1">
                      <div className="truncate font-medium text-foreground">
                        {s.title || s.url || 'Blank tab'}
                      </div>
                      <div className="truncate text-[11px] text-muted-foreground">{s.url}</div>
                    </div>
                    <span
                      role="button"
                      tabIndex={0}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (confirm('Close this session?')) close.mutate(s.id);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          if (confirm('Close this session?')) close.mutate(s.id);
                        }
                      }}
                      className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <main className="space-y-4">
          {activeId ? (
            <>
              <div className="rounded-xl border border-border bg-card p-4">
                <form
                  onSubmit={(e) => {
                    e.preventDefault();
                    if (!navUrl.trim()) return;
                    navigate.mutate({ id: activeId, url: navUrl.trim() });
                  }}
                  className="flex gap-2"
                >
                  <Input
                    value={navUrl}
                    onChange={(e) => setNavUrl(e.target.value)}
                    placeholder="https://example.com"
                    className="flex-1 font-mono text-xs"
                  />
                  <Button type="submit" size="sm" disabled={navigate.isPending}>
                    {navigate.isPending ? (
                      <Loader2 className="h-3.5 w-3.5 animate-spin" />
                    ) : (
                      <ArrowRight className="h-3.5 w-3.5" />
                    )}
                  </Button>
                </form>
                <div className="mt-3 flex gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => doExtract.mutate(activeId)}
                    disabled={doExtract.isPending}
                  >
                    <FileText className="mr-1.5 h-3.5 w-3.5" />
                    Extract
                  </Button>
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => doShot.mutate(activeId)}
                    disabled={doShot.isPending}
                  >
                    <ImageDown className="mr-1.5 h-3.5 w-3.5" />
                    Screenshot
                  </Button>
                </div>
              </div>

              {shotSrc && (
                <div className="rounded-xl border border-border bg-card p-3">
                  <p className="mb-2 text-xs text-muted-foreground">Latest screenshot</p>
                  {/* eslint-disable-next-line @next/next/no-img-element */}
                  <img
                    src={shotSrc}
                    alt="screenshot"
                    className="max-h-[600px] w-full rounded-md border border-border object-contain"
                  />
                </div>
              )}

              {extract && (
                <div className="rounded-xl border border-border bg-card p-3">
                  <h4 className="mb-1 truncate font-medium text-foreground">{extract.title}</h4>
                  <p className="mb-2 truncate text-[11px] text-muted-foreground">{extract.url}</p>
                  <pre className="max-h-[400px] overflow-auto whitespace-pre-wrap rounded-md bg-muted p-3 text-xs text-foreground">
                    {extract.text}
                  </pre>
                  {extract.links.length > 0 && (
                    <details className="mt-3">
                      <summary className="cursor-pointer text-xs text-muted-foreground">
                        {extract.links.length} links
                      </summary>
                      <ul className="mt-2 max-h-[200px] space-y-0.5 overflow-auto text-xs">
                        {extract.links.slice(0, 50).map((l, i) => (
                          <li key={i} className="truncate">
                            <a
                              href={l.href}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="text-primary hover:underline"
                            >
                              {l.text || l.href}
                            </a>
                          </li>
                        ))}
                      </ul>
                    </details>
                  )}
                </div>
              )}
            </>
          ) : (
            <div className="rounded-xl border border-dashed border-border p-10 text-center text-sm text-muted-foreground">
              Select or start a session to begin.
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Plug, Plus, Trash2, MessageSquare, AlertCircle } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { agentApi, toastApiError} from '@/lib/api';

type ChannelLink = {
  id: string;
  workspaceId: string | null;
  channel: string;
  externalId: string;
  label: string | null;
  enabled: boolean;
  createdAt: string;
};

type Status = {
  telegram: { enabled: boolean; webhookUrl: string | null };
};

export default function ChannelsPage() {
  const qc = useQueryClient();
  const [externalId, setExternalId] = useState('');
  const [labelText, setLabelText] = useState('');

  const { data: status } = useQuery({
    queryKey: ['channels-status'],
    queryFn: async () => {
      const res = await agentApi.get('/channels/status');
      return res.data as Status;
    },
    retry: false,
  });

  const { data, isLoading } = useQuery({
    queryKey: ['channel-links'],
    queryFn: async () => {
      const res = await agentApi.get('/channels/links');
      return (res.data?.links ?? []) as ChannelLink[];
    },
    retry: false,
  });
  const links = data ?? [];

  const create = useMutation({
    mutationFn: async () => {
      await agentApi.post('/channels/links', {
        channel: 'telegram',
        externalId: externalId.trim(),
        label: labelText.trim() || null,
      });
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['channel-links'] });
      toast.success('Telegram chat linked.');
      setExternalId('');
      setLabelText('');
    },
    onError: (e) => toastApiError(e, 'Could not link channel.'),
  });

  const toggle = useMutation({
    mutationFn: async ({ id, enabled }: { id: string; enabled: boolean }) => {
      await agentApi.patch(`/channels/links/${id}`, { enabled });
    },
    onSuccess: () => qc.invalidateQueries({ queryKey: ['channel-links'] }),
    onError: (e) => toastApiError(e, 'Could not update link.'),
  });

  const remove = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.delete(`/channels/links/${id}`);
    },
    onSuccess: () => {
      qc.invalidateQueries({ queryKey: ['channel-links'] });
      toast.success('Link removed.');
    },
    onError: (e) => toastApiError(e, 'Could not remove link.'),
  });

  const telegramOk = status?.telegram.enabled ?? false;
  const telegramHook = status?.telegram.webhookUrl ?? null;

  return (
    <div className="mx-auto max-w-3xl p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Plug className="h-5 w-5 text-primary" />
        </div>
        <div>
          <h2 className="text-lg font-semibold text-foreground">Channels</h2>
          <p className="text-sm text-muted-foreground">
            Reach the agent from outside the web UI. Link an external account here, then message
            the bot — replies come back automatically.
          </p>
        </div>
      </div>

      <section className="mt-6 rounded-xl border border-border bg-card p-4">
        <header className="mb-3 flex items-center gap-2">
          <MessageSquare className="h-4 w-4 text-primary" />
          <h3 className="font-medium text-foreground">Telegram</h3>
          <span
            className={`ml-auto rounded-full px-2 py-0.5 text-[11px] font-medium ${
              telegramOk
                ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400'
                : 'bg-amber-500/10 text-amber-600 dark:text-amber-400'
            }`}
          >
            {telegramOk ? 'Bot configured' : 'Token missing'}
          </span>
        </header>

        {!telegramOk && (
          <div className="mb-3 flex gap-2 rounded-lg border border-amber-500/30 bg-amber-500/5 p-3 text-xs text-amber-700 dark:text-amber-300">
            <AlertCircle className="h-4 w-4 shrink-0" />
            <span>
              Set <code className="font-mono">TELEGRAM_BOT_TOKEN</code> on the agent service env,
              register a webhook to{' '}
              <code className="font-mono">/api/channels/telegram/webhook</code>, and restart.
            </span>
          </div>
        )}
        {telegramHook && (
          <p className="mb-3 break-all text-[11px] text-muted-foreground">
            Webhook URL: <code className="font-mono">{telegramHook}</code>
          </p>
        )}

        <ol className="mb-4 list-decimal space-y-1 pl-5 text-xs text-muted-foreground">
          <li>
            Open the bot in Telegram and send <code className="font-mono">/start</code>.
          </li>
          <li>
            Find your numeric chat id (e.g. via <code className="font-mono">@userinfobot</code>).
          </li>
          <li>Paste it below and link it to your CloudMind account.</li>
        </ol>

        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (!externalId.trim()) return;
            create.mutate();
          }}
          className="grid grid-cols-1 gap-3 md:grid-cols-3"
        >
          <div className="space-y-1.5 md:col-span-1">
            <Label htmlFor="ch-id">Telegram chat id</Label>
            <Input
              id="ch-id"
              value={externalId}
              onChange={(e) => setExternalId(e.target.value)}
              placeholder="123456789"
              disabled={!telegramOk}
            />
          </div>
          <div className="space-y-1.5 md:col-span-1">
            <Label htmlFor="ch-label">Label (optional)</Label>
            <Input
              id="ch-label"
              value={labelText}
              onChange={(e) => setLabelText(e.target.value)}
              placeholder="My phone"
              disabled={!telegramOk}
            />
          </div>
          <div className="flex items-end">
            <Button
              size="sm"
              type="submit"
              disabled={!telegramOk || create.isPending || !externalId.trim()}
            >
              <Plus className="mr-1.5 h-3.5 w-3.5" />
              {create.isPending ? 'Linking...' : 'Link chat'}
            </Button>
          </div>
        </form>
      </section>

      <section className="mt-6">
        <h3 className="mb-3 text-sm font-semibold text-foreground">Linked accounts</h3>
        {isLoading ? (
          <p className="text-sm text-muted-foreground">Loading...</p>
        ) : links.length === 0 ? (
          <div className="rounded-xl border border-dashed border-border p-8 text-center text-sm text-muted-foreground">
            No links yet. Add a Telegram chat above to start receiving messages.
          </div>
        ) : (
          <div className="space-y-2">
            {links.map((l) => (
              <div
                key={l.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-3"
              >
                <div className="min-w-0">
                  <div className="flex items-center gap-2">
                    <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono uppercase text-muted-foreground">
                      {l.channel}
                    </span>
                    <span className="font-medium text-foreground">
                      {l.label || l.externalId}
                    </span>
                    {!l.enabled && (
                      <span className="rounded bg-amber-500/10 px-1.5 py-0.5 text-[10px] font-medium text-amber-600 dark:text-amber-400">
                        Disabled
                      </span>
                    )}
                  </div>
                  <p className="mt-0.5 text-xs text-muted-foreground">
                    External id: <code className="font-mono">{l.externalId}</code>
                  </p>
                </div>
                <div className="flex items-center gap-2">
                  <label className="flex cursor-pointer items-center gap-1 text-xs text-muted-foreground">
                    <input
                      type="checkbox"
                      checked={l.enabled}
                      onChange={(e) =>
                        toggle.mutate({ id: l.id, enabled: e.target.checked })
                      }
                    />
                    Enabled
                  </label>
                  <Button
                    size="sm"
                    variant="ghost"
                    className="text-destructive hover:text-destructive"
                    onClick={() => {
                      if (confirm('Remove this link?')) remove.mutate(l.id);
                    }}
                  >
                    <Trash2 className="h-3.5 w-3.5" />
                  </Button>
                </div>
              </div>
            ))}
          </div>
        )}
      </section>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { authApi } from '@/lib/api';
import { Users, FileText, Activity, Loader2, ShieldCheck, Clock } from 'lucide-react';
import { cn } from '@/lib/utils';
import { StatusBadge } from '@/components/ui/status-badge';

type AdminTab = 'users' | 'audit-logs' | 'health';

export default function AdminPage() {
  const [activeTab, setActiveTab] = useState<AdminTab>('users');

  const { data: usersData, isLoading: usersLoading } = useQuery({
    queryKey: ['admin-users'],
    queryFn: async () => {
      const res = await authApi.get('/admin/users');
      return res.data as { id: string; name: string | null; email: string; createdAt: string }[];
    },
    enabled: activeTab === 'users',
  });

  const { data: logsData, isLoading: logsLoading } = useQuery({
    queryKey: ['admin-audit-logs'],
    queryFn: async () => {
      const res = await authApi.get('/admin/audit-logs');
      return res.data as {
        id: string;
        userId: string | null;
        action: string;
        details: Record<string, unknown> | null;
        ipAddress: string | null;
        createdAt: string;
      }[];
    },
    enabled: activeTab === 'audit-logs',
  });

  const { data: healthData, isLoading: healthLoading } = useQuery({
    queryKey: ['admin-health'],
    queryFn: async () => {
      const res = await authApi.get('/admin/health');
      return res.data as { status: string; dbConnected: boolean; uptime: number };
    },
    enabled: activeTab === 'health',
  });

  const tabs = [
    { id: 'users' as const, label: 'Users', icon: Users },
    { id: 'audit-logs' as const, label: 'Audit Logs', icon: FileText },
    { id: 'health' as const, label: 'System Health', icon: Activity },
  ];

  return (
    <div className="mx-auto max-w-5xl p-6">
      <div className="flex items-center gap-3 mb-1">
        <ShieldCheck className="h-6 w-6 text-primary" />
        <h2 className="text-lg font-semibold text-foreground">Admin Panel</h2>
      </div>
      <p className="text-sm text-muted-foreground mb-6">System administration and monitoring</p>

      {/* Tab Navigation */}
      <div className="flex gap-1 border-b border-border mb-6">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            type="button"
            onClick={() => setActiveTab(tab.id)}
            className={cn(
              'flex items-center gap-2 px-4 py-2.5 text-sm font-medium border-b-2 -mb-px transition-colors',
              activeTab === tab.id
                ? 'border-primary text-primary'
                : 'border-transparent text-muted-foreground hover:text-foreground hover:border-muted-foreground/30',
            )}
          >
            <tab.icon className="h-4 w-4" />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Users Tab */}
      {activeTab === 'users' && (
        <div className="rounded-xl border border-border bg-card overflow-hidden">
          <div className="grid grid-cols-12 gap-4 p-4 text-xs font-semibold uppercase tracking-wider text-muted-foreground border-b border-border bg-muted/30">
            <div className="col-span-4">Name</div>
            <div className="col-span-4">Email</div>
            <div className="col-span-4">Joined</div>
          </div>
          {usersLoading ? (
            <div className="flex justify-center py-12">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : (usersData || []).length === 0 ? (
            <div className="py-12 text-center text-sm text-muted-foreground">No users found</div>
          ) : (
            <div className="divide-y divide-border">
              {(usersData || []).map((u) => (
                <div
                  key={u.id}
                  className="grid grid-cols-12 gap-4 p-4 text-sm items-center hover:bg-muted/20 transition-colors"
                >
                  <div className="col-span-4 font-medium text-foreground">{u.name || '—'}</div>
                  <div className="col-span-4 text-muted-foreground font-mono text-xs">
                    {u.email}
                  </div>
                  <div className="col-span-4 text-muted-foreground text-xs flex items-center gap-1.5">
                    <Clock className="h-3.5 w-3.5" />
                    {new Date(u.createdAt).toLocaleDateString()}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Audit Logs Tab */}
      {activeTab === 'audit-logs' && (
        <div className="rounded-xl border border-border bg-card overflow-hidden">
          <div className="grid grid-cols-12 gap-4 p-4 text-xs font-semibold uppercase tracking-wider text-muted-foreground border-b border-border bg-muted/30">
            <div className="col-span-3">Action</div>
            <div className="col-span-3">User ID</div>
            <div className="col-span-2">IP</div>
            <div className="col-span-4">Time</div>
          </div>
          {logsLoading ? (
            <div className="flex justify-center py-12">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : (logsData || []).length === 0 ? (
            <div className="py-12 text-center text-sm text-muted-foreground">No audit logs yet</div>
          ) : (
            <div className="divide-y divide-border max-h-[600px] overflow-y-auto">
              {(logsData || []).map((log) => (
                <div
                  key={log.id}
                  className="grid grid-cols-12 gap-4 p-4 text-sm items-center hover:bg-muted/20 transition-colors"
                >
                  <div className="col-span-3">
                    <StatusBadge
                      variant={
                        log.action.includes('login')
                          ? 'success'
                          : log.action.includes('failed')
                            ? 'error'
                            : log.action.includes('delete') || log.action.includes('REVOKE')
                              ? 'error'
                              : 'default'
                      }
                    >
                      {log.action}
                    </StatusBadge>
                  </div>
                  <div className="col-span-3 text-muted-foreground font-mono text-xs truncate">
                    {log.userId || '—'}
                  </div>
                  <div className="col-span-2 text-muted-foreground text-xs">
                    {log.ipAddress || '—'}
                  </div>
                  <div className="col-span-4 text-muted-foreground text-xs">
                    {new Date(log.createdAt).toLocaleString()}
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Health Tab */}
      {activeTab === 'health' && (
        <div className="space-y-4">
          {healthLoading ? (
            <div className="flex justify-center py-12">
              <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
            </div>
          ) : healthData ? (
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="rounded-xl border border-border bg-card p-6 text-center">
                <Activity
                  className={cn(
                    'mx-auto h-8 w-8 mb-2',
                    healthData.status === 'healthy' ? 'text-green-500' : 'text-red-500',
                  )}
                />
                <p className="text-sm font-semibold text-foreground capitalize">
                  {healthData.status}
                </p>
                <p className="text-xs text-muted-foreground mt-1">System Status</p>
              </div>
              <div className="rounded-xl border border-border bg-card p-6 text-center">
                <div
                  className={cn(
                    'mx-auto h-8 w-8 rounded-full mb-2 flex items-center justify-center',
                    healthData.dbConnected
                      ? 'bg-green-500/10 text-green-500'
                      : 'bg-red-500/10 text-red-500',
                  )}
                >
                  {healthData.dbConnected ? '✓' : '✗'}
                </div>
                <p className="text-sm font-semibold text-foreground">
                  {healthData.dbConnected ? 'Connected' : 'Disconnected'}
                </p>
                <p className="text-xs text-muted-foreground mt-1">Database</p>
              </div>
              <div className="rounded-xl border border-border bg-card p-6 text-center">
                <Clock className="mx-auto h-8 w-8 mb-2 text-primary" />
                <p className="text-sm font-semibold text-foreground">
                  {Math.floor(healthData.uptime / 3600)}h{' '}
                  {Math.floor((healthData.uptime % 3600) / 60)}m
                </p>
                <p className="text-xs text-muted-foreground mt-1">Uptime</p>
              </div>
            </div>
          ) : (
            <div className="py-12 text-center text-sm text-muted-foreground">
              Could not fetch health data. Are you an admin?
            </div>
          )}
        </div>
      )}
    </div>
  );
}

'use client';

import { useMemo, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { History, RefreshCw } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { authApi, getApiErrorMessage } from '@/lib/api';

type AuditLog = {
  id: string;
  userId: string | null;
  action: string;
  details: Record<string, unknown> | null;
  ipAddress: string | null;
  userAgent: string | null;
  createdAt: string;
};

function formatTime(iso: string) {
  try {
    const d = new Date(iso);
    return d.toLocaleString();
  } catch {
    return iso;
  }
}

export default function AuditLogPage() {
  const [filter, setFilter] = useState('');
  const [actionFilter, setActionFilter] = useState('');

  const { data, isLoading, error, refetch, isRefetching } = useQuery({
    queryKey: ['user-audit-logs', actionFilter],
    queryFn: async () => {
      const res = await authApi.get('/user/audit-logs', {
        params: actionFilter ? { action: actionFilter, limit: 200 } : { limit: 200 },
      });
      return res.data as AuditLog[];
    },
    retry: false,
  });

  const filtered = useMemo(() => {
    if (!data) return [];
    if (!filter.trim()) return data;
    const q = filter.toLowerCase();
    return data.filter(
      (log) =>
        log.action.toLowerCase().includes(q) ||
        (log.ipAddress?.toLowerCase().includes(q) ?? false) ||
        JSON.stringify(log.details ?? {}).toLowerCase().includes(q),
    );
  }, [data, filter]);

  const actions = useMemo(() => {
    if (!data) return [] as string[];
    return Array.from(new Set(data.map((d) => d.action))).sort();
  }, [data]);

  return (
    <div className="mx-auto max-w-5xl p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <History className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Audit Log</h2>
          <p className="text-sm text-muted-foreground">
            Privileged actions on your account: tool runs, hosted-service changes, snapshot
            restores, channel links, BYOK key add/revoke, and login events.
          </p>
        </div>
        <Button
          variant="outline"
          size="sm"
          onClick={() => refetch()}
          disabled={isRefetching}
        >
          <RefreshCw className={`mr-1 h-3.5 w-3.5 ${isRefetching ? 'animate-spin' : ''}`} />
          Refresh
        </Button>
      </div>

      <div className="mt-6 flex flex-wrap gap-3">
        <Input
          placeholder="Search action, IP, or details..."
          value={filter}
          onChange={(e) => setFilter(e.target.value)}
          className="max-w-xs"
        />
        <select
          className="h-9 rounded-md border border-border bg-background px-3 text-sm"
          value={actionFilter}
          onChange={(e) => setActionFilter(e.target.value)}
        >
          <option value="">All actions</option>
          {actions.map((a) => (
            <option key={a} value={a}>
              {a}
            </option>
          ))}
        </select>
      </div>

      <div className="mt-4 rounded-xl border border-border bg-card">
        {isLoading ? (
          <div className="p-6 text-sm text-muted-foreground">Loading...</div>
        ) : error ? (
          <div className="p-6 text-sm text-destructive">
            {getApiErrorMessage(error, 'Failed to load audit log.')}
          </div>
        ) : filtered.length === 0 ? (
          <div className="p-6 text-sm text-muted-foreground">No entries.</div>
        ) : (
          <div className="divide-y divide-border">
            {filtered.map((log) => (
              <div key={log.id} className="px-4 py-3">
                <div className="flex flex-wrap items-baseline justify-between gap-2">
                  <code className="rounded bg-muted px-2 py-0.5 font-mono text-xs text-foreground">
                    {log.action}
                  </code>
                  <span className="text-xs text-muted-foreground">
                    {formatTime(log.createdAt)}
                    {log.ipAddress ? ` · ${log.ipAddress}` : ''}
                  </span>
                </div>
                {log.details && Object.keys(log.details).length > 0 ? (
                  <pre className="mt-2 overflow-x-auto rounded bg-muted/40 p-2 text-xs text-muted-foreground">
                    {JSON.stringify(log.details, null, 2)}
                  </pre>
                ) : null}
              </div>
            ))}
          </div>
        )}
      </div>

      <p className="mt-3 text-xs text-muted-foreground">
        Showing the most recent 200 entries. Filter narrows by action server-side.
      </p>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Camera, RotateCcw } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import {workspaceApi , toastApiError} from '@/lib/api';
import { formatDate } from '@/lib/format';

type WorkspacesResponse = {
  workspaces?: { id: string }[];
};

type Snapshot = {
  id: string;
  name: string;
  description?: string | null;
  createdAt: string;
};

export default function SnapshotsPage() {
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [restoreTarget, setRestoreTarget] = useState<Snapshot | null>(null);

  // We need a workspaceId. For now, get user's first workspace.
  const { data: wsData } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaceId = wsData?.workspaces?.[0]?.id;

  const { data: snapshots, isLoading } = useQuery({
    queryKey: ['snapshots', workspaceId],
    enabled: Boolean(workspaceId),
    queryFn: async () => {
      const res = await workspaceApi.get(`/workspaces/${workspaceId}/snapshots`);
      return (res.data as { snapshots: Snapshot[] }).snapshots;
    },
  });

  const createMutation = useMutation({
    mutationFn: async () => {
      await workspaceApi.post(`/workspaces/${workspaceId}/snapshots`, { name, description });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot created');
      setShowCreate(false);
      setName('');
      setDescription('');
    },
    onError: (e) => toastApiError(e, 'Failed to create snapshot'),
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.post(`/snapshots/${id}/restore`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot restored. A safety backup was created.');
      setRestoreTarget(null);
    },
    onError: (e) => toastApiError(e, 'Failed to restore'),
  });

  const items = snapshots || [];

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Snapshots</h2>
          <p className="text-sm text-muted-foreground">Backup and restore your workspace</p>
        </div>
        <Button size="sm" onClick={() => setShowCreate((v) => !v)} disabled={!workspaceId}>
          <Camera className="mr-1.5 h-3.5 w-3.5" />
          Create Snapshot
        </Button>
      </div>

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (name.trim()) createMutation.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-[1fr_1fr_auto] md:items-end"
        >
          <div className="space-y-1.5">
            <Label htmlFor="snap-name">Name</Label>
            <Input
              id="snap-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Before refactoring"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="snap-desc">Description (optional)</Label>
            <Input
              id="snap-desc"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Details about this state..."
            />
          </div>
          <Button type="submit" size="sm" disabled={!name.trim() || createMutation.isPending}>
            {createMutation.isPending ? 'Creating...' : 'Create'}
          </Button>
        </form>
      )}

      <div className="mt-6">
        {isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : items.length > 0 ? (
          <div className="space-y-3">
            {items.map((snap) => (
              <div
                key={snap.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
              >
                <div className="flex min-w-0 items-center gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                    <Camera className="h-5 w-5 text-primary" />
                  </div>
                  <div className="min-w-0">
                    <h3 className="font-medium text-foreground">{snap.name}</h3>
                    <p className="text-xs text-muted-foreground">
                      {snap.description || 'No description'} · {formatDate(snap.createdAt)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" variant="outline" onClick={() => setRestoreTarget(snap)}>
                    <RotateCcw className="mr-1 h-3.5 w-3.5" /> Restore
                  </Button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState
            icon={<Camera className="h-6 w-6" />}
            title="No snapshots yet"
            description="Create a snapshot to backup your current workspace state. You can restore it anytime."
            action={{
              label: 'Create first snapshot',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(restoreTarget)}
        onOpenChange={() => setRestoreTarget(null)}
        title="Restore snapshot"
        description={`This will overwrite your current workspace with "${restoreTarget?.name}". A safety backup will be created automatically before the restore begins. This cannot be undone.`}
        confirmLabel="Yes, restore"
        variant="destructive"
        onConfirm={async () => {
          if (restoreTarget) await restoreMutation.mutateAsync(restoreTarget.id);
        }}
      />
    </div>
  );
}

