import { spawnSync } from 'node:child_process';
import { existsSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { pathToFileURL } from 'node:url';

const ALL_PACKAGE_FILTERS = [
  '--filter',
  'web',
  '--filter',
  '@pcp/db',
  '--filter',
  '@pcp/shared',
  '--filter',
  '@pcp/auth-service',
