'use client';

import { useMemo, useRef, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Database, Upload, Trash2, Play, Eye, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import axios from 'axios';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { workspaceApi, apiEndpoints, toastApiError} from '@/lib/api';

type Dataset = {
  id: string;
  name: string;
  tableName: string;
  sourceType: string;
  sourceFilename: string | null;
  columns: Array<{ name: string; type: string }>;
  rowCount: number;
  sizeBytes: number;
  createdAt: string;
};

type QueryResult = {
  columns: Array<{ name: string; type: string }>;
  rows: unknown[][];
  rowCount: number;
  truncated: boolean;
  durationMs: number;
};

const ACCEPT = '.csv,.tsv,.json,.ndjson,.jsonl,.parquet';

export default function DatasetsPage() {
  const qc = useQueryClient();
  const fileRef = useRef<HTMLInputElement>(null);
  const [activeId, setActiveId] = useState<string | null>(null);
  const [sql, setSql] = useState('');
  const [result, setResult] = useState<QueryResult | null>(null);

  const { data, isLoading } = useQuery({
    queryKey: ['datasets'],
    queryFn: async () => {
      const res = await workspaceApi.get('/datasets');
      return (res.data?.datasets ?? []) as Dataset[];
    },
    retry: false,
  });
  const datasets = useMemo(() => data ?? [], [data]);
  const active = useMemo(
    () => datasets.find((d) => d.id === activeId) ?? null,
    [datasets, activeId],
  );

  const importMut = useMutation({
    mutationFn: async (file: File) => {
      const fd = new FormData();
      fd.append('file', file);
      fd.append('name', file.name.replace(/\.[^.]+$/, ''));
      const res = await axios.post(`${apiEndpoints.workspace}/datasets/import`, fd, {
        withCredentials: true,
        headers: { 'Content-Type': 'multipart/form-data' },
      });
      return res.data as Dataset;
    },
    onSuccess: (ds) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      setActiveId(ds.id);
      setSql(`SELECT * FROM "${ds.tableName}" LIMIT 100`);
      toast.success(
        `Imported ${ds.rowCount.toLocaleString()} rows from ${ds.sourceFilename ?? ds.name}.`,
      );
    },
    onError: (e) => toastApiError(e, 'Import failed.'),
  });

  const removeMut = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.delete(`/datasets/${id}`);
    },
    onSuccess: (_, id) => {
      qc.invalidateQueries({ queryKey: ['datasets'] });
      if (activeId === id) {
        setActiveId(null);
        setResult(null);
      }
      toast.success('Dataset removed.');
    },
    onError: (e) => toastApiError(e, 'Could not remove dataset.'),
  });

  const queryMut = useMutation({
    mutationFn: async (q: string) => {
      const res = await workspaceApi.post(`/datasets/query`, { sql: q, rowLimit: 500 });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Query failed.'),
  });

  const previewMut = useMutation({
    mutationFn: async (id: string) => {
      const res = await workspaceApi.get(`/datasets/${id}/preview`, { params: { limit: 50 } });
      return res.data as QueryResult;
    },
    onSuccess: (r) => setResult(r),
    onError: (e) => toastApiError(e, 'Preview failed.'),
  });

  const onPickFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const f = e.target.files?.[0];
    if (!f) return;
    importMut.mutate(f);
    e.target.value = '';
  };

  return (
    <div className="mx-auto flex max-w-6xl flex-col gap-6 p-6">
      <div className="flex items-center gap-3">
        <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary/10">
          <Database className="h-5 w-5 text-primary" />
        </div>
        <div className="flex-1">
          <h2 className="text-lg font-semibold text-foreground">Datasets</h2>
          <p className="text-sm text-muted-foreground">
            Upload CSV, JSON, or Parquet files into your private DuckDB and query them with SQL.
          </p>
        </div>
        <input ref={fileRef} type="file" accept={ACCEPT} onChange={onPickFile} className="hidden" />
        <Button onClick={() => fileRef.current?.click()} disabled={importMut.isPending}>
          {importMut.isPending ? (
            <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
          ) : (
            <Upload className="mr-1.5 h-3.5 w-3.5" />
          )}
          {importMut.isPending ? 'Importing...' : 'Import file'}
        </Button>
      </div>

      <div className="grid grid-cols-1 gap-4 md:grid-cols-[260px_1fr]">
        <aside className="rounded-xl border border-border bg-card p-3">
          <h3 className="mb-2 px-1 text-xs font-medium uppercase tracking-wide text-muted-foreground">
            Catalog
          </h3>
          {isLoading ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">Loading...</p>
          ) : datasets.length === 0 ? (
            <p className="px-2 py-4 text-sm text-muted-foreground">
              No datasets yet. Import a file to get started.
            </p>
          ) : (
            <ul className="space-y-1">
              {datasets.map((d) => (
                <li key={d.id}>
                  <button
                    type="button"
                    onClick={() => {
                      setActiveId(d.id);
                      setSql(`SELECT * FROM "${d.tableName}" LIMIT 100`);
                    }}
                    className={`group flex w-full items-start justify-between gap-2 rounded-lg px-2 py-2 text-left text-sm transition-colors hover:bg-muted ${
                      activeId === d.id ? 'bg-muted' : ''
                    }`}
                  >
                    <div className="min-w-0 flex-1">
                      <div className="truncate font-medium text-foreground">{d.name}</div>
                      <div className="truncate text-[11px] text-muted-foreground">
                        {d.tableName} · {d.rowCount.toLocaleString()} rows · {d.columns.length} cols
                      </div>
                    </div>
                    <span
                      role="button"
                      tabIndex={0}
                      onClick={(e) => {
                        e.stopPropagation();
                        if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          if (confirm(`Remove dataset "${d.name}"?`)) removeMut.mutate(d.id);
                        }
                      }}
                      className="opacity-0 group-hover:opacity-100 text-muted-foreground hover:text-destructive"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </span>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </aside>

        <main className="space-y-4">
          {active ? (
            <div className="rounded-xl border border-border bg-card p-4">
              <div className="mb-3 flex flex-wrap items-center gap-2">
                <h3 className="font-medium text-foreground">{active.name}</h3>
                <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-mono uppercase text-muted-foreground">
                  {active.sourceType}
                </span>
                <span className="text-xs text-muted-foreground">
                  table <code className="font-mono">{active.tableName}</code>
                </span>
                <Button
                  size="sm"
                  variant="outline"
                  onClick={() => previewMut.mutate(active.id)}
                  disabled={previewMut.isPending}
                  className="ml-auto"
                >
                  <Eye className="mr-1.5 h-3.5 w-3.5" />
                  Preview
                </Button>
              </div>

              <div className="mb-2">
                <Label className="text-xs text-muted-foreground">SQL</Label>
                <textarea
                  value={sql}
                  onChange={(e) => setSql(e.target.value)}
                  rows={5}
                  className="mt-1 w-full rounded-md border border-input bg-background px-3 py-2 font-mono text-xs text-foreground focus:outline-none focus:ring-2 focus:ring-ring"
                  placeholder={`SELECT * FROM "${active.tableName}" LIMIT 100`}
                />
              </div>
              <div className="flex justify-end">
                <Button
                  size="sm"
                  onClick={() => sql.trim() && queryMut.mutate(sql)}
                  disabled={!sql.trim() || queryMut.isPending}
                >
                  {queryMut.isPending ? (
                    <Loader2 className="mr-1.5 h-3.5 w-3.5 animate-spin" />
                  ) : (
                    <Play className="mr-1.5 h-3.5 w-3.5" />
                  )}
                  Run
                </Button>
              </div>
            </div>
          ) : (
            <div className="rounded-xl border border-dashed border-border p-10 text-center text-sm text-muted-foreground">
              Select a dataset on the left or import a new file.
            </div>
          )}

          {result && (
            <div className="rounded-xl border border-border bg-card p-3">
              <div className="mb-2 flex items-center justify-between text-xs text-muted-foreground">
                <span>
                  {result.rowCount} rows · {result.durationMs}ms
                  {result.truncated && ' · truncated'}
                </span>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-xs">
                  <thead>
                    <tr className="border-b border-border">
                      {result.columns.map((c) => (
                        <th
                          key={c.name}
                          className="whitespace-nowrap px-2 py-1.5 text-left font-medium text-foreground"
                        >
                          {c.name}
                          <span className="ml-1 text-[10px] font-normal text-muted-foreground">
                            {c.type}
                          </span>
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {result.rows.map((row, i) => (
                      <tr key={i} className="border-b border-border/50 last:border-0">
                        {row.map((cell, j) => (
                          <td
                            key={j}
                            className="max-w-[280px] truncate whitespace-nowrap px-2 py-1 font-mono text-muted-foreground"
                          >
                            {formatCell(cell)}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
}

function formatCell(v: unknown): string {
  if (v === null || v === undefined) return '—';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean' || typeof v === 'bigint') return String(v);
  try {
    return JSON.stringify(v);
  } catch {
    return String(v);
  }
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Camera, RotateCcw } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import {workspaceApi , toastApiError} from '@/lib/api';
import { formatDate } from '@/lib/format';

type WorkspacesResponse = {
  workspaces?: { id: string }[];
};

type Snapshot = {
  id: string;
  name: string;
  description?: string | null;
  createdAt: string;
};

export default function SnapshotsPage() {
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [restoreTarget, setRestoreTarget] = useState<Snapshot | null>(null);

  // We need a workspaceId. For now, get user's first workspace.
  const { data: wsData } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaceId = wsData?.workspaces?.[0]?.id;

  const { data: snapshots, isLoading } = useQuery({
    queryKey: ['snapshots', workspaceId],
    enabled: Boolean(workspaceId),
    queryFn: async () => {
      const res = await workspaceApi.get(`/workspaces/${workspaceId}/snapshots`);
      return (res.data as { snapshots: Snapshot[] }).snapshots;
    },
  });

  const createMutation = useMutation({
    mutationFn: async () => {
      await workspaceApi.post(`/workspaces/${workspaceId}/snapshots`, { name, description });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot created');
      setShowCreate(false);
      setName('');
      setDescription('');
    },
    onError: (e) => toastApiError(e, 'Failed to create snapshot'),
  });

  const restoreMutation = useMutation({
    mutationFn: async (id: string) => {
      await workspaceApi.post(`/snapshots/${id}/restore`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['snapshots'] });
      toast.success('Snapshot restored. A safety backup was created.');
      setRestoreTarget(null);
    },
    onError: (e) => toastApiError(e, 'Failed to restore'),
  });

  const items = snapshots || [];

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Snapshots</h2>
          <p className="text-sm text-muted-foreground">Backup and restore your workspace</p>
        </div>
        <Button size="sm" onClick={() => setShowCreate((v) => !v)} disabled={!workspaceId}>
          <Camera className="mr-1.5 h-3.5 w-3.5" />
          Create Snapshot
        </Button>
      </div>

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (name.trim()) createMutation.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-[1fr_1fr_auto] md:items-end"
        >
          <div className="space-y-1.5">
            <Label htmlFor="snap-name">Name</Label>
            <Input
              id="snap-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="Before refactoring"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="snap-desc">Description (optional)</Label>
            <Input
              id="snap-desc"
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Details about this state..."
            />
          </div>
          <Button type="submit" size="sm" disabled={!name.trim() || createMutation.isPending}>
            {createMutation.isPending ? 'Creating...' : 'Create'}
          </Button>
        </form>
      )}

      <div className="mt-6">
        {isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : items.length > 0 ? (
          <div className="space-y-3">
            {items.map((snap) => (
              <div
                key={snap.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
              >
                <div className="flex min-w-0 items-center gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                    <Camera className="h-5 w-5 text-primary" />
                  </div>
                  <div className="min-w-0">
                    <h3 className="font-medium text-foreground">{snap.name}</h3>
                    <p className="text-xs text-muted-foreground">
                      {snap.description || 'No description'} · {formatDate(snap.createdAt)}
                    </p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <Button size="sm" variant="outline" onClick={() => setRestoreTarget(snap)}>
                    <RotateCcw className="mr-1 h-3.5 w-3.5" /> Restore
                  </Button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState
            icon={<Camera className="h-6 w-6" />}
            title="No snapshots yet"
            description="Create a snapshot to backup your current workspace state. You can restore it anytime."
            action={{
              label: 'Create first snapshot',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(restoreTarget)}
        onOpenChange={() => setRestoreTarget(null)}
        title="Restore snapshot"
        description={`This will overwrite your current workspace with "${restoreTarget?.name}". A safety backup will be created automatically before the restore begins. This cannot be undone.`}
        confirmLabel="Yes, restore"
        variant="destructive"
        onConfirm={async () => {
          if (restoreTarget) await restoreMutation.mutateAsync(restoreTarget.id);
        }}
      />
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  Clock3,
  History,
  Loader2,
  MoreHorizontal,
  Pause,
  Play,
  Plus,
  Trash2,
  Webhook,
  Zap,
} from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { EmptyState } from '@/components/ui/empty-state';
import { StatusBadge } from '@/components/ui/status-badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { agentApi, apiEndpoints, toastApiError} from '@/lib/api';
import { cn } from '@/lib/utils';
import { CreateAutomationDialog } from '@/components/automations/create-automation-dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';

type Tab = 'active' | 'paused' | 'history';

type Automation = {
  id: string;
  title: string;
  enabled: boolean;
  scheduleType: 'manual' | 'hourly' | 'daily' | 'weekly' | 'cron';
  cronExpression?: string | null;
  prompt?: string | null;
  lastRunAt?: string | null;
  nextRunAt?: string | null;
  notificationMode?: string | null;
};

type AutomationRun = {
  id: string;
  status: 'queued' | 'running' | 'completed' | 'failed';
  trigger: string;
  startedAt: string | null;
  finishedAt: string | null;
  durationMs: string | null;
  error: string | null;
  output: string | null;
  createdAt: string;
};

const tabs: { id: Tab; label: string }[] = [
  { id: 'active', label: 'Active' },
  { id: 'paused', label: 'Paused' },
  { id: 'history', label: 'History' },
];

function formatRelative(value: string | null | undefined) {
  if (!value) return '—';
  const diff = new Date(value).getTime() - Date.now();
  const abs = Math.abs(diff);
  const min = Math.round(abs / 60_000);
  if (min < 1) return diff >= 0 ? 'in <1m' : 'just now';
  if (min < 60) return diff >= 0 ? `in ${min}m` : `${min}m ago`;
  const hr = Math.round(min / 60);
  if (hr < 24) return diff >= 0 ? `in ${hr}h` : `${hr}h ago`;
  const day = Math.round(hr / 24);
  return diff >= 0 ? `in ${day}d` : `${day}d ago`;
}

function describeSchedule(a: Automation) {
  if (a.scheduleType === 'cron' && a.cronExpression) return `cron · ${a.cronExpression}`;
  return a.scheduleType;
}

export default function AutomationsPage() {
  const [activeTab, setActiveTab] = useState<Tab>('active');
  const [historyId, setHistoryId] = useState<string | null>(null);
  const [createOpen, setCreateOpen] = useState(false);
  const queryClient = useQueryClient();

  const { data: automations, isLoading } = useQuery({
    queryKey: ['automations'],
    queryFn: async () => {
      const res = await agentApi.get('/automations');
      const payload = res.data as { automations: Automation[] } | Automation[];
      return Array.isArray(payload) ? payload : payload.automations;
    },
  });

  const toggleMutation = useMutation({
    mutationFn: async ({ id, enabled }: { id: string; enabled: boolean }) => {
      await agentApi.patch(`/automations/${id}`, { enabled });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation updated');
    },
    onError: (e) => toastApiError(e, 'Failed to update'),
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.delete(`/automations/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation deleted');
    },
    onError: (e) => toastApiError(e, 'Failed to delete'),
  });

  const runMutation = useMutation({
    mutationFn: async (id: string) => {
      await agentApi.post(`/automations/${id}/run`);
    },
    onSuccess: () => {
      toast.success('Automation triggered');
    },
    onError: (e) => toastApiError(e, 'Failed to run'),
  });

  const copyWebhookUrl = useMutation({
    mutationFn: async (id: string) => {
      const res = await agentApi.get(`/automations/${id}/trigger-token`);
      const { token } = res.data as { token: string };
      const url = `${apiEndpoints.agent}/automations/${id}/trigger?token=${token}`;
      await navigator.clipboard.writeText(url);
      return url;
    },
    onSuccess: () => toast.success('Webhook URL copied'),
    onError: (e) => toastApiError(e, 'Failed to fetch token'),
  });

  const all = automations || [];
  const filtered =
    activeTab === 'active'
      ? all.filter((a) => a.enabled)
      : activeTab === 'paused'
        ? all.filter((a) => !a.enabled)
        : all;

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Automations</h2>
          <p className="text-sm text-muted-foreground">Schedule AI tasks to run automatically</p>
        </div>
        <Button size="sm" onClick={() => setCreateOpen(true)}>
          <Plus className="mr-1.5 h-3.5 w-3.5" />
          Create Automation
        </Button>
      </div>

      <div className="mt-4 flex gap-1 border-b border-border">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            type="button"
            onClick={() => setActiveTab(tab.id)}
            className={cn(
              'border-b-2 px-4 py-2 text-sm font-medium transition-colors',
              activeTab === tab.id
                ? 'border-primary text-primary'
                : 'border-transparent text-muted-foreground hover:text-foreground',
            )}
          >
            {tab.label}
          </button>
        ))}
      </div>

      <div className="mt-6">
        {isLoading ? (
          <div className="flex justify-center py-12">
            <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
          </div>
        ) : filtered.length > 0 ? (
          <div className="space-y-3">
            {filtered.map((auto) => (
              <div
                key={auto.id}
                className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
              >
                <div className="flex min-w-0 items-center gap-3">
                  <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                    <Zap className="h-5 w-5 text-primary" />
                  </div>
                  <div className="min-w-0">
                    <div className="flex items-center gap-2">
                      <h3 className="truncate font-medium text-foreground">{auto.title}</h3>
                      <StatusBadge variant={auto.enabled ? 'success' : 'stopped'} dot>
                        {auto.enabled ? 'Active' : 'Paused'}
                      </StatusBadge>
                    </div>
                    <p className="truncate text-xs text-muted-foreground">
                      {describeSchedule(auto)}
                      {auto.prompt ? ` · ${auto.prompt.slice(0, 60)}…` : ''}
                    </p>
                    <div className="mt-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[11px] text-muted-foreground">
                      <span title={auto.nextRunAt ?? undefined}>
                        Next: <span className="text-foreground/80">{formatRelative(auto.nextRunAt)}</span>
                      </span>
                      <span title={auto.lastRunAt ?? undefined}>
                        Last: <span className="text-foreground/80">{formatRelative(auto.lastRunAt)}</span>
                      </span>
                      {auto.notificationMode && auto.notificationMode !== 'none' && (
                        <span>Notify: {auto.notificationMode}</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <Button
                    size="sm"
                    variant="outline"
                    onClick={() => runMutation.mutate(auto.id)}
                    disabled={runMutation.isPending}
                  >
                    <Play className="mr-1 h-3.5 w-3.5" /> Run
                  </Button>
                  <DropdownMenu>
                    <DropdownMenuTrigger
                      render={(props) => (
                        <Button {...props} size="sm" variant="ghost">
                          <MoreHorizontal className="h-4 w-4" />
                        </Button>
                      )}
                    />
                    <DropdownMenuContent align="end">
                      <DropdownMenuItem onClick={() => setHistoryId(auto.id)}>
                        <History className="mr-2 h-4 w-4" /> View history
                      </DropdownMenuItem>
                      <DropdownMenuItem onClick={() => copyWebhookUrl.mutate(auto.id)}>
                        <Webhook className="mr-2 h-4 w-4" /> Copy webhook URL
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        onClick={() =>
                          toggleMutation.mutate({ id: auto.id, enabled: !auto.enabled })
                        }
                      >
                        {auto.enabled ? (
                          <>
                            <Pause className="mr-2 h-4 w-4" /> Pause
                          </>
                        ) : (
                          <>
                            <Play className="mr-2 h-4 w-4" /> Resume
                          </>
                        )}
                      </DropdownMenuItem>
                      <DropdownMenuItem
                        className="text-destructive"
                        onClick={() => deleteMutation.mutate(auto.id)}
                      >
                        <Trash2 className="mr-2 h-4 w-4" /> Delete
                      </DropdownMenuItem>
                    </DropdownMenuContent>
                  </DropdownMenu>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <EmptyState
            icon={<Clock3 className="h-6 w-6" />}
            title={`No ${activeTab} automations`}
            description="Create an automation to schedule AI tasks like file processing, reports, or backups."
            action={{
              label: 'Create automation',
              onClick: () => setCreateOpen(true),
            }}
          />
        )}
      </div>

      <CreateAutomationDialog open={createOpen} onOpenChange={setCreateOpen} />

      <RunHistoryDialog
        automationId={historyId}
        onOpenChange={(open) => !open && setHistoryId(null)}
      />
    </div>
  );
}

function RunHistoryDialog({
  automationId,
  onOpenChange,
}: {
  automationId: string | null;
  onOpenChange: (open: boolean) => void;
}) {
  const { data, isLoading } = useQuery({
    queryKey: ['automation-runs', automationId],
    queryFn: async () => {
      if (!automationId) return { runs: [] as AutomationRun[] };
      const res = await agentApi.get(`/automations/${automationId}/runs`);
      return res.data as { runs: AutomationRun[] };
    },
    enabled: !!automationId,
    refetchInterval: automationId ? 5_000 : false,
  });

  return (
    <Dialog open={!!automationId} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Run history</DialogTitle>
        </DialogHeader>
        <div className="max-h-[60vh] overflow-y-auto">
          {isLoading ? (
            <div className="flex justify-center py-8">
              <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
            </div>
          ) : data && data.runs.length > 0 ? (
            <div className="space-y-2">
              {data.runs.map((run) => {
                const variant: 'success' | 'error' | 'info' | 'stopped' =
                  run.status === 'completed'
                    ? 'success'
                    : run.status === 'failed'
                      ? 'error'
                      : run.status === 'running'
                        ? 'info'
                        : 'stopped';
                const duration = run.durationMs
                  ? `${(Number(run.durationMs) / 1000).toFixed(1)}s`
                  : '—';
                return (
                  <div
                    key={run.id}
                    className="rounded-lg border border-border bg-card p-3 text-xs"
                  >
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        <StatusBadge variant={variant} dot>
                          {run.status}
                        </StatusBadge>
                        <span className="text-muted-foreground">{run.trigger}</span>
                      </div>
                      <span className="text-muted-foreground">
                        {new Date(run.createdAt).toLocaleString()}
                      </span>
                    </div>
                    <div className="mt-1 flex gap-3 text-[11px] text-muted-foreground">
                      <span>Duration: {duration}</span>
                    </div>
                    {run.error && (
                      <pre className="mt-2 max-h-32 overflow-auto rounded bg-destructive/10 p-2 text-[11px] text-destructive">
                        {run.error}
                      </pre>
                    )}
                    {run.output && (
                      <pre className="mt-2 max-h-32 overflow-auto rounded bg-muted/50 p-2 text-[11px] text-foreground/80">
                        {run.output}
                      </pre>
                    )}
                  </div>
                );
              })}
            </div>
          ) : (
            <p className="py-8 text-center text-sm text-muted-foreground">No runs yet.</p>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useEffect, useMemo, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { agentApi, workspaceApi , toastApiError} from '@/lib/api';
import { cn } from '@/lib/utils';

type ScheduleType = 'manual' | 'hourly' | 'daily' | 'weekly' | 'cron';
type NotificationMode = 'none' | 'in-app' | 'email-mock' | 'webhook';

type WorkspaceSummary = { id: string; name: string };

interface CreateAutomationDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function CreateAutomationDialog({ open, onOpenChange }: CreateAutomationDialogProps) {
  const queryClient = useQueryClient();
  const [title, setTitle] = useState('');
  const [prompt, setPrompt] = useState('');
  const [workspaceId, setWorkspaceId] = useState<string>('');
  const [scheduleType, setScheduleType] = useState<ScheduleType>('manual');
  const [cronExpression, setCronExpression] = useState('');
  const [notificationMode, setNotificationMode] = useState<NotificationMode>('in-app');
  const [webhookUrl, setWebhookUrl] = useState('');

  const { data: workspacesData } = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as { workspaces: WorkspaceSummary[] };
    },
    enabled: open,
  });
  const workspaces = useMemo(
    () => workspacesData?.workspaces ?? [],
    [workspacesData],
  );

  useEffect(() => {
    if (open && !workspaceId && workspaces.length > 0 && workspaces[0]) {
      // Default-select the first workspace when the dialog opens; the
      // selection is user-overridable so the cascading-render warning is
      // not applicable here.
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setWorkspaceId(workspaces[0].id);
    }
  }, [open, workspaces, workspaceId]);

  const reset = () => {
    setTitle('');
    setPrompt('');
    setScheduleType('manual');
    setCronExpression('');
    setNotificationMode('in-app');
    setWebhookUrl('');
  };

  const createMutation = useMutation({
    mutationFn: async () => {
      const body: Record<string, unknown> = {
        title: title.trim(),
        prompt: prompt.trim(),
        scheduleType,
        notificationMode,
        enabled: true,
      };
      if (workspaceId) body.workspaceId = workspaceId;
      if (scheduleType === 'cron') body.cronExpression = cronExpression.trim();
      if (notificationMode === 'webhook') body.webhookUrl = webhookUrl.trim();

      const res = await agentApi.post('/automations', body);
      return res.data;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['automations'] });
      toast.success('Automation created');
      reset();
      onOpenChange(false);
    },
    onError: (e) => toastApiError(e, 'Failed to create automation'),
  });

  const valid =
    title.trim().length > 0 &&
    prompt.trim().length > 0 &&
    (scheduleType !== 'cron' || cronExpression.trim().length > 0) &&
    (notificationMode !== 'webhook' || /^https?:\/\//i.test(webhookUrl.trim()));

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Create automation</DialogTitle>
        </DialogHeader>

        <div className="space-y-3">
          <div className="space-y-1.5">
            <Label htmlFor="auto-title">Title</Label>
            <Input
              id="auto-title"
              placeholder="Daily standup summary"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              maxLength={200}
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="auto-prompt">Prompt</Label>
            <Textarea
              id="auto-prompt"
              placeholder="Summarize today's commits and post to /workspace/standup.md"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              rows={4}
            />
          </div>

          <div className="space-y-1.5">
            <Label htmlFor="auto-workspace">Workspace</Label>
            <NativeSelect
              id="auto-workspace"
              value={workspaceId}
              onChange={(e) => setWorkspaceId(e.target.value)}
            >
              <option value="">Select workspace…</option>
              {workspaces.map((w) => (
                <option key={w.id} value={w.id}>
                  {w.name}
                </option>
              ))}
            </NativeSelect>
          </div>

          <div className="grid grid-cols-2 gap-3">
            <div className="space-y-1.5">
              <Label htmlFor="auto-schedule">Schedule</Label>
              <NativeSelect
                id="auto-schedule"
                value={scheduleType}
                onChange={(e) => setScheduleType(e.target.value as ScheduleType)}
              >
                <option value="manual">Manual / webhook only</option>
                <option value="hourly">Hourly (top of hour)</option>
                <option value="daily">Daily at 09:00 UTC</option>
                <option value="weekly">Weekly Mon 09:00 UTC</option>
                <option value="cron">Custom cron</option>
              </NativeSelect>
            </div>

            <div className="space-y-1.5">
              <Label htmlFor="auto-notify">Notify</Label>
              <NativeSelect
                id="auto-notify"
                value={notificationMode}
                onChange={(e) => setNotificationMode(e.target.value as NotificationMode)}
              >
                <option value="none">None</option>
                <option value="in-app">In-app only</option>
                <option value="email-mock">Email (mock)</option>
                <option value="webhook">Webhook POST</option>
              </NativeSelect>
            </div>
          </div>

          {scheduleType === 'cron' && (
            <div className="space-y-1.5">
              <Label htmlFor="auto-cron">Cron expression</Label>
              <Input
                id="auto-cron"
                placeholder="*/15 * * * *"
                value={cronExpression}
                onChange={(e) => setCronExpression(e.target.value)}
                className="font-mono"
              />
              <p className="text-[11px] text-muted-foreground">
                Standard 5-field cron. Next-run estimate is hidden for custom cron schedules.
              </p>
            </div>
          )}

          {notificationMode === 'webhook' && (
            <div className="space-y-1.5">
              <Label htmlFor="auto-webhook">Webhook URL</Label>
              <Input
                id="auto-webhook"
                type="url"
                placeholder="https://example.com/hooks/automation"
                value={webhookUrl}
                onChange={(e) => setWebhookUrl(e.target.value)}
              />
              <p className="text-[11px] text-muted-foreground">
                Each run POSTs JSON with an <code className="font-mono">X-Pcp-Signature</code>{' '}
                header (HMAC SHA-256).
              </p>
            </div>
          )}
        </div>

        <DialogFooter>
          <Button variant="ghost" onClick={() => onOpenChange(false)}>
            Cancel
          </Button>
          <Button
            onClick={() => createMutation.mutate()}
            disabled={!valid || createMutation.isPending}
          >
            {createMutation.isPending && <Loader2 className="mr-2 h-3.5 w-3.5 animate-spin" />}
            Create
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function NativeSelect({
  className,
  ...props
}: React.SelectHTMLAttributes<HTMLSelectElement>) {
  return (
    <select
      className={cn(
        'flex h-9 w-full rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm',
        'focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring',
        'disabled:cursor-not-allowed disabled:opacity-50',
        className,
      )}
      {...props}
    />
  );
}

import { FastifyInstance, FastifyRequest } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { promises as fs } from 'node:fs';
import * as os from 'node:os';
import * as path from 'node:path';
import { pipeline } from 'node:stream/promises';
import { createWriteStream } from 'node:fs';
import {
  datasetResponseSchema,
  queryDatasetSchema,
  queryResultSchema,
  apiErrorCodeFromStatus,
  sendApiError,
} from '@pcp/shared';
import { DatasetsService } from '../datasets/service';
import { env } from '../env';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';

const SOURCE_TYPE_BY_EXT: Record<string, 'csv' | 'json' | 'parquet'> = {
  '.csv': 'csv',
  '.tsv': 'csv',
  '.json': 'json',
  '.ndjson': 'json',
  '.jsonl': 'json',
  '.parquet': 'parquet',
};

function toResponse(row: any) {
  return {
    id: row.id,
    name: row.name,
    tableName: row.tableName,
    sourceType: row.sourceType,
    sourceFilename: row.sourceFilename ?? null,
    columns: Array.isArray(row.columns) ? row.columns : [],
    rowCount: Number(row.rowCount ?? 0),
    sizeBytes: Number(row.sizeBytes ?? 0),
    version: Number(row.version ?? 1),
    createdAt: row.createdAt instanceof Date ? row.createdAt.toISOString() : row.createdAt,
    updatedAt: row.updatedAt instanceof Date ? row.updatedAt.toISOString() : row.updatedAt,
  };
}

export async function setupDatasetsRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();
  const datasetsService = new DatasetsService(fastify.log);

  async function authUser(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request, {
      internalServiceToken: env.INTERNAL_SERVICE_TOKEN,
    });
  }

  server.get(
    '/datasets',
    {
      schema: {
        response: {
          200: z.object({ datasets: z.array(datasetResponseSchema) }),
        },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const rows = await datasetsService.list(userId);
      return { datasets: rows.map(toResponse) };
    },
  );

  server.delete(
    '/datasets/:id',
    {
      schema: { params: z.object({ id: z.string().uuid() }) },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        await datasetsService.remove(userId, request.params.id);
        return { success: true };
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Internal error',
        );
      }
    },
  );

  server.post(
    '/datasets/:id/query',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const ds = await datasetsService.get(userId, request.params.id);
      if (!ds) return sendApiError(reply, 404, 'NOT_FOUND', 'Dataset not found');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.post(
    '/datasets/query',
    {
      schema: {
        body: queryDatasetSchema,
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.query({
          userId,
          sql: request.body.sql,
          rowLimit: request.body.rowLimit,
        });
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        if (status === 500) fastify.log.error({ err }, 'dataset query failed');
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Query failed',
        );
      }
    },
  );

  server.get(
    '/datasets/:id/preview',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        querystring: z.object({ limit: z.coerce.number().int().min(1).max(500).optional() }),
        response: { 200: queryResultSchema },
      },
    },
    async (request, reply) => {
      const userId = await authUser(request);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      try {
        return await datasetsService.preview(userId, request.params.id, request.query.limit);
      } catch (err: any) {
        const status = err?.statusCode ?? 500;
        return sendApiError(
          reply,
          status,
          apiErrorCodeFromStatus(status),
          err?.message ?? 'Preview failed',
        );
      }
    },
  );

  // Multipart upload + import. Field name for the file part is "file"; an optional
  // text field "name" overrides the dataset display name.
  server.post('/datasets/import', async (request, reply) => {
    const userId = await authUser(request);
    if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

    if (!request.isMultipart()) {
      return sendApiError(reply, 400, 'BAD_REQUEST', 'Expected multipart/form-data');
    }

    let displayName: string | undefined;
    let savedPath: string | undefined;
    let originalFilename: string | undefined;
    let sourceType: 'csv' | 'json' | 'parquet' | undefined;

    try {
      const tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'cloudmind-ds-'));
      const parts = request.parts();
      for await (const part of parts) {
        if (part.type === 'field' && part.fieldname === 'name') {
          displayName = String(part.value);
        } else if (part.type === 'file') {
          originalFilename = part.filename;
          const ext = path.extname(part.filename).toLowerCase();
          const detected = SOURCE_TYPE_BY_EXT[ext];
          if (!detected) {
            await part.file.resume();
            return sendApiError(
              reply,
              400,
              'BAD_REQUEST',
              `Unsupported file type "${ext}". Use .csv, .tsv, .json, .ndjson, or .parquet.`,
            );
          }
          sourceType = detected;
          savedPath = path.join(tmpDir, `upload${ext}`);
          await pipeline(part.file, createWriteStream(savedPath));
        }
      }

      if (!savedPath || !sourceType || !originalFilename) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'No file provided');
      }

      const finalName =
        (displayName?.trim() || path.basename(originalFilename, path.extname(originalFilename))) ||
        'dataset';

      const inserted = await datasetsService.importFile({
        userId,
        name: finalName,
        filePath: savedPath,
        sourceFilename: originalFilename,
        sourceType,
      });
      return reply.code(201).send(toResponse(inserted));
    } catch (err: any) {
      const status = err?.statusCode ?? 500;
      if (status === 500) fastify.log.error({ err }, 'dataset import failed');
      return sendApiError(
        reply,
        status,
        apiErrorCodeFromStatus(status),
        err?.message ?? 'Import failed',
      );
    } finally {
      if (savedPath) {
        await fs.rm(path.dirname(savedPath), { recursive: true, force: true }).catch(() => {});
      }
    }
  });
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { createSnapshotSchema, snapshotResponseSchema, sendApiError } from '@pcp/shared';
import { WorkspaceService } from '../service';
import { db } from '@pcp/db/src/client';
import { auditLogs } from '@pcp/db/src/schema';

async function emitAudit(
  fastify: FastifyInstance,
  userId: string | null,
  action: string,
  details: Record<string, unknown>,
): Promise<void> {
  try {
    await db.insert(auditLogs).values({ userId, action, details });
  } catch (e) {
    fastify.log.warn({ action, err: e }, 'audit_log emit failed');
  }
}

export async function setupSnapshotRoutes(
  fastify: FastifyInstance,
  workspaceService: WorkspaceService,
) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();

  server.post(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: createSnapshotSchema.omit({ workspaceId: true }),
        response: {
          201: snapshotResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshot = await workspaceService.createSnapshot(
        request.params.id,
        userId,
        request.body.name,
        request.body.description,
      );

      return reply.code(201).send(snapshot);
    },
  );

  server.get(
    '/workspaces/:id/snapshots',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        response: {
          200: z.object({
            snapshots: z.array(snapshotResponseSchema),
          }),
        },
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const snapshots = await workspaceService.getSnapshots(request.params.id, userId);
      return { snapshots };
    },
  );

  server.post(
    '/snapshots/:id/restore',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const result = await workspaceService.restoreSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_RESTORE', { snapshotId: request.params.id });
      return { success: true, ...result };
    },
  );

  server.delete(
    '/snapshots/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await workspaceService.validateUserFromCookie(request.cookies.sessionId || '');
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      await workspaceService.deleteSnapshot(request.params.id, userId);
      await emitAudit(fastify, userId, 'SNAPSHOT_DELETE', { snapshotId: request.params.id });
      return { success: true };
    },
  );
}

import { FastifyInstance } from 'fastify';
import { ZodTypeProvider } from 'fastify-type-provider-zod';
import { db } from '@pcp/db/src/client';
import { automations, automationRuns, workspaces } from '@pcp/db/src/schema';
import { validateSessionUserId } from '@pcp/db/src/session';
import { and, eq, desc, isNull } from 'drizzle-orm';
import { createAutomationSchema, updateAutomationSchema, sendApiError } from '@pcp/shared';
import { automationQueue } from '../automation/queue';
import { automationRepeatKey, computeNextRunAt, resolveSchedule } from '../automation/schedule';
import { automationTriggerToken, verifyAutomationTriggerToken } from '../automation/notify';
import { z } from 'zod';

export async function setupAutomationRoutes(fastify: FastifyInstance) {
  const server = fastify.withTypeProvider<ZodTypeProvider>();

  async function getAuthenticatedUserId(sessionId: string | undefined): Promise<string | null> {
    return validateSessionUserId(sessionId);
  }

  async function assertWorkspaceOwned(workspaceId: string | undefined | null, userId: string) {
    if (!workspaceId) return true;
    const workspace = await db.query.workspaces.findFirst({
      where: and(
        eq(workspaces.id, workspaceId),
        eq(workspaces.userId, userId),
        isNull(workspaces.deletedAt),
      ),
    });
    return Boolean(workspace);
  }

  server.get(
    '/automations',
    {
      schema: {
        querystring: z.object({ workspaceId: z.string().uuid().optional() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');
      const { workspaceId } = request.query;

      if (!(await assertWorkspaceOwned(workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const items = await db.query.automations.findMany({
        where: workspaceId
          ? and(eq(automations.userId, userId), eq(automations.workspaceId, workspaceId))
          : eq(automations.userId, userId),
        orderBy: [desc(automations.createdAt)],
      });

      return { automations: items };
    },
  );

  server.post(
    '/automations',
    {
      schema: { body: createAutomationSchema },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const nextRunAt = computeNextRunAt(request.body);

      const [automation] = await db
        .insert(automations)
        .values({
          userId,
          ...request.body,
          nextRunAt,
        })
        .returning();
      if (!automation) throw new Error('Failed to create automation');

      const schedule = resolveSchedule(automation);
      if (automation.enabled && schedule.isRepeating && schedule.pattern) {
        await automationQueue.add(
          'scheduled-run',
          { automationId: automation.id },
          {
            repeat: {
              pattern: schedule.pattern,
              ...(schedule.timezone ? { tz: schedule.timezone } : {}),
            },
            jobId: automationRepeatKey(automation.id),
          },
        );
      }

      return reply.code(201).send({
        ...automation,
        triggerToken: automationTriggerToken(automation.id),
      });
    },
  );

  server.patch(
    '/automations/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateAutomationSchema,
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;

      if (!(await assertWorkspaceOwned(request.body.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const nextRunAt = computeNextRunAt({
        scheduleType: request.body.scheduleType ?? 'manual',
        cronExpression: request.body.cronExpression ?? null,
        timezone: request.body.timezone ?? null,
      });

      const [updated] = await db
        .update(automations)
        .set({
          ...request.body,
          ...(request.body.scheduleType !== undefined ? { nextRunAt } : {}),
          updatedAt: new Date(),
        })
        .where(and(eq(automations.id, id), eq(automations.userId, userId)))
        .returning();

      if (!updated) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      // Re-register the repeat: always remove the existing key first; then add
      // a fresh repeat job if the automation is enabled and has a schedule.
      try {
        await automationQueue.removeRepeatableByKey(automationRepeatKey(id));
      } catch {
        // ignore — key may not exist
      }
      const schedule = resolveSchedule(updated);
      if (updated.enabled && schedule.isRepeating && schedule.pattern) {
        await automationQueue.add(
          'scheduled-run',
          { automationId: updated.id },
          {
            repeat: {
              pattern: schedule.pattern,
              ...(schedule.timezone ? { tz: schedule.timezone } : {}),
            },
            jobId: automationRepeatKey(updated.id),
          },
        );
      }

      return updated;
    },
  );

  server.delete(
    '/automations/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      await db
        .delete(automations)
        .where(and(eq(automations.id, id), eq(automations.userId, userId)));
      try {
        await automationQueue.removeRepeatableByKey(automationRepeatKey(id));
      } catch {
        // ignore
      }

      return { success: true };
    },
  );

  // Manual trigger
  server.post(
    '/automations/:id/run',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, id), eq(automations.userId, userId)),
      });

      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');
      if (!automation.workspaceId) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'Automation missing workspace');
      }
      if (!(await assertWorkspaceOwned(automation.workspaceId, userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      // Create a run record
      const [run] = await db
        .insert(automationRuns)
        .values({
          automationId: automation.id,
          userId,
          trigger: 'manual',
          status: 'queued',
        })
        .returning();
      if (!run) throw new Error('Failed to create run');

      // Add to BullMQ
      await automationQueue.add('manual-run', {
        runId: run.id,
        automationId: automation.id,
        userId,
        workspaceId: automation.workspaceId,
        prompt: automation.prompt,
      });

      return run;
    },
  );

  // Get runs
  server.get(
    '/automations/:id/runs',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const { id } = request.params;
      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, id), eq(automations.userId, userId)),
      });
      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      const runs = await db.query.automationRuns.findMany({
        where: and(eq(automationRuns.automationId, id), eq(automationRuns.userId, userId)),
        orderBy: [desc(automationRuns.createdAt)],
      });

      return { runs };
    },
  );

  // Return the inbound webhook trigger token. Callers use this to construct a
  // public webhook URL that can fire a manual run without a session cookie.
  server.get(
    '/automations/:id/trigger-token',
    {
      schema: { params: z.object({ id: z.string().uuid() }) },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request.cookies.sessionId);
      if (!userId) return sendApiError(reply, 401, 'UNAUTHORIZED');

      const automation = await db.query.automations.findFirst({
        where: and(eq(automations.id, request.params.id), eq(automations.userId, userId)),
      });
      if (!automation) return sendApiError(reply, 404, 'NOT_FOUND', 'Not found');

      return { token: automationTriggerToken(automation.id) };
    },
  );

  // Inbound public webhook trigger. Validated via constant-time HMAC token
  // (no session cookie required). Always enqueues a manual run.
  server.post(
    '/automations/:id/trigger',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        querystring: z.object({ token: z.string().min(8) }),
      },
    },
    async (request, reply) => {
      const { id } = request.params;
      const { token } = request.query;

      if (!verifyAutomationTriggerToken(id, token)) {
        return sendApiError(reply, 401, 'UNAUTHORIZED', 'Invalid trigger token');
      }

      const automation = await db.query.automations.findFirst({
        where: eq(automations.id, id),
      });
      if (!automation || !automation.enabled) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Automation not found or disabled');
      }
      if (!automation.workspaceId) {
        return sendApiError(reply, 400, 'BAD_REQUEST', 'Automation missing workspace');
      }
      if (!(await assertWorkspaceOwned(automation.workspaceId, automation.userId))) {
        return sendApiError(reply, 404, 'NOT_FOUND', 'Workspace not found');
      }

      const [run] = await db
        .insert(automationRuns)
        .values({
          automationId: automation.id,
          userId: automation.userId,
          trigger: 'webhook',
          status: 'queued',
        })
        .returning();
      if (!run) throw new Error('Failed to create run');

      await automationQueue.add('webhook-run', {
        runId: run.id,
        automationId: automation.id,
        userId: automation.userId,
        workspaceId: automation.workspaceId,
        prompt: automation.prompt,
      });

      return reply.code(202).send({ runId: run.id });
    },
  );
}

'use client';

import { useMemo, useState } from 'react';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import {
  ExternalLink,
  Globe2,
  Play,
  RefreshCw,
  Rocket,
  Server,
  Square,
  Trash2,
} from 'lucide-react';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { EmptyState } from '@/components/ui/empty-state';
import { LoadingSkeleton } from '@/components/ui/loading-skeleton';
import { StatusBadge } from '@/components/ui/status-badge';
import { ConfirmDialog } from '@/components/ui/confirm-dialog';
import { WorkspaceSummary } from '@/components/workspace/create-workspace-dialog';
import {publishApi, workspaceApi , toastApiError} from '@/lib/api';
import { formatDate } from '@/lib/format';
import { useUser } from '@/lib/auth';

type WorkspacesResponse = {
  workspaces: WorkspaceSummary[];
  page: number;
  limit: number;
};

type HostedService = {
  id: string;
  workspaceId: string;
  name: string;
  slug: string;
  status: string;
  kind: string;
  updatedAt: string;
  publicUrl?: string | null;
  autoRestart?: boolean;
  crashCount?: number;
  lastHealthAt?: string | null;
  lastHealthOk?: boolean | null;
};

export default function HostingPage() {
  const { data: user } = useUser();
  const queryClient = useQueryClient();
  const [showCreate, setShowCreate] = useState(false);
  const [name, setName] = useState('');
  const [slug, setSlug] = useState('');
  const [kind, setKind] = useState('static');
  const [rootPath, setRootPath] = useState('/');
  const [workspaceId, setWorkspaceId] = useState('');
  const [deleteTarget, setDeleteTarget] = useState<string | null>(null);

  const workspacesQuery = useQuery({
    queryKey: ['workspaces'],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces');
      return res.data as WorkspacesResponse;
    },
  });

  const workspaces = useMemo(
    () => workspacesQuery.data?.workspaces ?? [],
    [workspacesQuery.data],
  );
  const defaultWorkspaceId = workspaceId || workspaces[0]?.id || '';

  const servicesQuery = useQuery({
    queryKey: ['hosted-services', defaultWorkspaceId],
    enabled: Boolean(user?.id && defaultWorkspaceId),
    retry: false,
    refetchInterval: 20_000,
    queryFn: async () => {
      const res = await publishApi.get('/hosted-services', {
        params: { workspaceId: defaultWorkspaceId },
      });
      return res.data as HostedService[];
    },
  });

  const services = servicesQuery.data ?? [];
  const hostingReady = Boolean(user?.id && !servicesQuery.isError);

  const workspaceNameById = useMemo(() => {
    return new Map(workspaces.map((w) => [w.id, w.name]));
  }, [workspaces]);

  const createService = useMutation({
    mutationFn: async () => {
      if (!user?.id) throw new Error('You must be signed in.');
      await publishApi.post('/hosted-services', {
        workspaceId: defaultWorkspaceId,
        name: name.trim(),
        slug: normalizeSlug(slug || name),
        kind,
        rootPath,
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service created.');
      setShowCreate(false);
      setName('');
      setSlug('');
      setKind('static');
      setRootPath('/');
    },
    onError: (e) => toastApiError(e, 'Could not create service.'),
  });

  const startService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/start`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service starting...');
    },
    onError: (e) => toastApiError(e, 'Could not start service.'),
  });

  const stopService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/stop`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service stopped.');
    },
    onError: (e) => toastApiError(e, 'Could not stop service.'),
  });

  const restartService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.post(`/hosted-services/${id}/restart`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service restarting...');
    },
    onError: (e) => toastApiError(e, 'Could not restart service.'),
  });

  const updateAutoRestart = useMutation({
    mutationFn: async ({ id, autoRestart }: { id: string; autoRestart: boolean }) => {
      await publishApi.patch(`/hosted-services/${id}`, { autoRestart });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
    },
    onError: (e) => toastApiError(e, 'Could not update service.'),
  });

  const deleteService = useMutation({
    mutationFn: async (id: string) => {
      await publishApi.delete(`/hosted-services/${id}`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['hosted-services'] });
      toast.success('Service deleted.');
      setDeleteTarget(null);
    },
    onError: (e) => toastApiError(e, 'Could not delete service.'),
  });

  const canCreate = hostingReady && Boolean(defaultWorkspaceId && name.trim());

  return (
    <div className="mx-auto max-w-4xl p-6">
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-lg font-semibold text-foreground">Hosting</h2>
          <p className="text-sm text-muted-foreground">Deploy workspace apps as hosted services</p>
        </div>
        <Button
          size="sm"
          onClick={() => setShowCreate((v) => !v)}
          disabled={!hostingReady || workspaces.length === 0}
        >
          <Rocket className="mr-1.5 h-3.5 w-3.5" />
          Create service
        </Button>
      </div>

      {servicesQuery.isError && (
        <div className="mt-4 rounded-lg border border-amber-500/30 bg-amber-500/5 p-3 text-sm text-amber-600 dark:text-amber-400">
          Publish service is not available. Hosting actions are disabled until it responds.
        </div>
      )}

      {showCreate && (
        <form
          onSubmit={(e) => {
            e.preventDefault();
            if (canCreate) createService.mutate();
          }}
          className="mt-4 grid gap-4 rounded-xl border border-border bg-card p-4 md:grid-cols-2 lg:grid-cols-3"
        >
          <div className="space-y-1.5">
            <Label htmlFor="svc-name">Service name</Label>
            <Input
              id="svc-name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My App"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-slug">Slug (subdomain)</Label>
            <Input
              id="svc-slug"
              value={slug}
              onChange={(e) => setSlug(e.target.value)}
              placeholder={normalizeSlug(name || 'my-app')}
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-kind">Kind</Label>
            <select
              id="svc-kind"
              value={kind}
              onChange={(e) => setKind(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              <option value="static">Static (HTML/CSS/JS)</option>
              <option value="vite">Vite App</option>
              <option value="node">Node.js API</option>
            </select>
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-root">Root path</Label>
            <Input
              id="svc-root"
              value={rootPath}
              onChange={(e) => setRootPath(e.target.value)}
              placeholder="/"
            />
          </div>
          <div className="space-y-1.5">
            <Label htmlFor="svc-workspace">Workspace</Label>
            <select
              id="svc-workspace"
              value={defaultWorkspaceId}
              onChange={(e) => setWorkspaceId(e.target.value)}
              className="h-8 w-full rounded-lg border border-border bg-card px-3 text-sm text-foreground"
            >
              {workspaces.map((w) => (
                <option key={w.id} value={w.id}>
                  {w.name}
                </option>
              ))}
            </select>
          </div>
          <div className="flex items-end">
            <Button type="submit" size="sm" disabled={!canCreate || createService.isPending}>
              {createService.isPending ? 'Creating...' : 'Create'}
            </Button>
          </div>
        </form>
      )}

      <div className="mt-6">
        {servicesQuery.isLoading ? (
          <LoadingSkeleton variant="card" />
        ) : services.length > 0 ? (
          <div className="space-y-3">
            {services.map((svc) => {
              const isRunning = svc.status === 'running';
              const isStarting = svc.status === 'starting';
              return (
                <div
                  key={svc.id}
                  className="flex items-center justify-between rounded-xl border border-border bg-card p-4"
                >
                  <div className="flex min-w-0 items-center gap-3">
                    <div className="flex h-10 w-10 shrink-0 items-center justify-center rounded-lg bg-primary/10">
                      <Server className="h-5 w-5 text-primary" />
                    </div>
                    <div className="min-w-0">
                      <div className="flex items-center gap-2">
                        <h3 className="font-medium text-foreground">{svc.name}</h3>
                        <StatusBadge
                          variant={isRunning ? 'running' : isStarting ? 'pending' : 'stopped'}
                          dot
                        >
                          {svc.status}
                        </StatusBadge>
                        <span className="rounded bg-muted px-1.5 py-0.5 text-[10px] font-semibold uppercase tracking-wider text-muted-foreground">
                          {svc.kind}
                        </span>
                      </div>
                      <p className="text-xs text-muted-foreground">
                        {svc.slug}.apps.localhost ·{' '}
                        {workspaceNameById.get(svc.workspaceId) || 'Workspace'} ·{' '}
                        {formatDate(svc.updatedAt)}
                      </p>
                      <div className="mt-1 flex flex-wrap gap-x-3 gap-y-0.5 text-[11px] text-muted-foreground">
                        <span
                          className={
                            svc.lastHealthOk === false
                              ? 'text-destructive'
                              : svc.lastHealthOk
                                ? 'text-emerald-600 dark:text-emerald-400'
                                : ''
                          }
                          title={svc.lastHealthAt ?? undefined}
                        >
                          Health:{' '}
                          {svc.lastHealthOk === null || svc.lastHealthOk === undefined
                            ? '—'
                            : svc.lastHealthOk
                              ? 'OK'
                              : 'failing'}
                        </span>
                        <span>Crashes: {svc.crashCount ?? 0}</span>
                        <label className="flex cursor-pointer items-center gap-1">
                          <input
                            type="checkbox"
                            checked={svc.autoRestart ?? true}
                            onChange={(e) =>
                              updateAutoRestart.mutate({
                                id: svc.id,
                                autoRestart: e.target.checked,
                              })
                            }
                            className="h-3 w-3"
                          />
                          Auto-restart
                        </label>
                      </div>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {isRunning ? (
                      <>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => restartService.mutate(svc.id)}
                          disabled={restartService.isPending}
                          title="Restart"
                        >
                          <RefreshCw className="mr-1 h-3.5 w-3.5" /> Restart
                        </Button>
                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => stopService.mutate(svc.id)}
                          disabled={stopService.isPending}
                        >
                          <Square className="mr-1 h-3.5 w-3.5" /> Stop
                        </Button>
                      </>
                    ) : (
                      <Button
                        size="sm"
                        variant="outline"
                        onClick={() => startService.mutate(svc.id)}
                        disabled={startService.isPending || isStarting}
                      >
                        <Play className="mr-1 h-3.5 w-3.5" /> Start
                      </Button>
                    )}
                    {svc.publicUrl && (
                      <a href={svc.publicUrl} target="_blank" rel="noreferrer">
                        <Button size="sm" variant="outline">
                          Open <ExternalLink className="ml-1 h-3.5 w-3.5" />
                        </Button>
                      </a>
                    )}
                    <Button
                      size="sm"
                      variant="ghost"
                      className="text-destructive hover:text-destructive"
                      onClick={() => setDeleteTarget(svc.id)}
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        ) : (
          <EmptyState
            icon={<Globe2 className="h-6 w-6" />}
            title="No services yet"
            description="Create a static site, Vite app, or Node.js service from an existing workspace."
            action={{
              label: 'Create service',
              onClick: () => setShowCreate(true),
            }}
          />
        )}
      </div>

      <ConfirmDialog
        open={Boolean(deleteTarget)}
        onOpenChange={() => setDeleteTarget(null)}
        title="Delete service"
        description="This will stop the running container and remove the service. This action cannot be undone."
        confirmLabel="Delete"
        variant="destructive"
        onConfirm={async () => {
          if (deleteTarget) await deleteService.mutateAsync(deleteTarget);
        }}
      />
    </div>
  );
}

function normalizeSlug(value: string) {
  return value
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9-]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 48);
}

import { FastifyPluginAsyncZod } from 'fastify-type-provider-zod';
import { z } from 'zod';
import { PublishService } from './service';
import {
  createApiErrorResponse,
  createHostedServiceSchema,
  apiErrorResponseSchema,
  updateHostedServiceSchema,
  hostedServiceResponseSchema,
} from '@pcp/shared';
import { resolveAuthenticatedUserId } from '@pcp/db/src/auth-request';
import { FastifyReply, FastifyRequest } from 'fastify';

function sendUnauthorized(reply: FastifyReply) {
  return reply.code(401).send(createApiErrorResponse('UNAUTHORIZED', 'Unauthorized'));
}

export const publishRoutes: FastifyPluginAsyncZod = async (app) => {
  const publishService = new PublishService();

  async function getAuthenticatedUserId(request: FastifyRequest): Promise<string | null> {
    return resolveAuthenticatedUserId(request);
  }

  app.post(
    '/hosted-services',
    {
      schema: {
        body: createHostedServiceSchema,
        response: {
          201: hostedServiceResponseSchema,
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const service = await publishService.createService({ ...request.body, userId });
      return reply.code(201).send(service);
    },
  );

  app.get(
    '/hosted-services',
    {
      schema: {
        querystring: z.object({
          workspaceId: z.string().uuid(),
        }),
        response: {
          200: z.array(hostedServiceResponseSchema),
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const services = await publishService.listServices(request.query.workspaceId, userId);
      return reply.code(200).send(services);
    },
  );

  app.patch(
    '/hosted-services/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
        body: updateHostedServiceSchema,
        response: {
          200: hostedServiceResponseSchema,
          401: apiErrorResponseSchema,
        },
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const service = await publishService.updateService(request.params.id, userId, request.body);
      return reply.code(200).send(service);
    },
  );

  app.delete(
    '/hosted-services/:id',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      await publishService.deleteService(request.params.id, userId);
      return reply.code(204).send();
    },
  );

  app.post(
    '/hosted-services/:id/start',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const result = await publishService.startService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );

  app.post(
    '/hosted-services/:id/stop',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      const result = await publishService.stopService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );

  app.post(
    '/hosted-services/:id/restart',
    {
      schema: {
        params: z.object({ id: z.string().uuid() }),
      },
    },
    async (request, reply) => {
      const userId = await getAuthenticatedUserId(request);
      if (!userId) return sendUnauthorized(reply);

      await publishService.stopService(request.params.id, userId);
      const result = await publishService.startService(request.params.id, userId);
      return reply.code(200).send(result);
    },
  );
};

'use client';

import { useMemo, useState, useCallback } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { ChevronDown, ChevronRight, File as FileIcon, Folder, FolderOpen, Pencil, Trash, Download } from 'lucide-react';
import { toast } from 'sonner';
import { workspaceApi, toastApiError} from '@/lib/api';
import { formatBytes, formatDate } from '@/lib/format';
import { cn } from '@/lib/utils';
import { useWorkspaceStore, WorkspaceFileMetadata } from '@/store/workspace';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from '@/components/ui/context-menu';

type FilesResponse = {
  files: WorkspaceFileMetadata[];
};

export default function FileTree({ workspaceId }: { workspaceId: string }) {
  const { selectedItem } = useWorkspaceStore();
  const queryClient = useQueryClient();
  const [isDragging, setIsDragging] = useState(false);

  const uploadMutation = useMutation({
    mutationFn: async (file: File) => {
      const formData = new FormData();
      formData.append('file', file);
      formData.append('path', `/${file.name}`);

      await workspaceApi.post(`/workspaces/${workspaceId}/upload`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('File uploaded successfully');
    },
    onError: (err) => {
      toastApiError(err, 'Failed to upload file');
    },
  });

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setIsDragging(false);

      if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
        Array.from(e.dataTransfer.files).forEach((file) => {
          uploadMutation.mutate(file);
        });
      }
    },
    [uploadMutation]
  );

  return (
    <div 
      className={cn(
        "flex h-full flex-col text-sm transition-colors",
        isDragging && "bg-primary/5 ring-1 ring-inset ring-primary"
      )}
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      <div className="flex h-10 items-center px-4 text-xs font-semibold uppercase tracking-wider text-muted-foreground">
        Explorer
      </div>
      <div className="min-h-0 flex-1 overflow-auto py-1">
        {isDragging && (
          <div className="absolute inset-0 z-10 flex items-center justify-center bg-background/50 backdrop-blur-sm">
            <div className="rounded-xl border border-primary/20 bg-card p-4 text-center shadow-lg">
              <Download className="mx-auto mb-2 h-6 w-6 text-primary" />
              <p className="text-sm font-medium">Drop files to upload</p>
            </div>
          </div>
        )}
        <TreeBranch workspaceId={workspaceId} path="/" level={0} />
      </div>
      <div className="border-t border-border bg-card p-3">
        <p className="mb-2 text-xs font-semibold uppercase tracking-wider text-muted-foreground">Details</p>
        {selectedItem ? (
          <dl className="space-y-1.5 text-xs">
            <div>
              <dt className="text-muted-foreground">Name</dt>
              <dd className="truncate text-foreground">{selectedItem.name}</dd>
            </div>
            <div>
              <dt className="text-muted-foreground">Path</dt>
              <dd className="truncate text-foreground">{selectedItem.path}</dd>
            </div>
            <div className="grid grid-cols-2 gap-2">
              <div>
                <dt className="text-muted-foreground">Type</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? 'Folder' : selectedItem.mimeType || 'File'}</dd>
              </div>
              <div>
                <dt className="text-muted-foreground">Size</dt>
                <dd className="text-foreground">{selectedItem.isDirectory ? '-' : formatBytes(selectedItem.size)}</dd>
              </div>
            </div>
            <div>
              <dt className="text-muted-foreground">Updated</dt>
              <dd className="text-foreground">{formatDate(selectedItem.updatedAt)}</dd>
            </div>
          </dl>
        ) : (
          <p className="text-xs text-muted-foreground">Select a file or folder to inspect.</p>
        )}
      </div>
    </div>
  );
}

function TreeBranch({ workspaceId, path, level }: { workspaceId: string; path: string; level: number }) {
  const [expandedPaths, setExpandedPaths] = useState<Set<string>>(new Set());
  const { selectedItem, setSelectedFile, addOpenFile, setSelectedItem, removeOpenFile } = useWorkspaceStore();
  const queryClient = useQueryClient();

  const { data, isLoading, isError } = useQuery({
    queryKey: ['workspace-files', workspaceId, path],
    queryFn: async () => {
      const res = await workspaceApi.get('/workspaces/' + workspaceId + '/files', { params: { path } });
      return res.data as FilesResponse;
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (filePath: string) => {
      await workspaceApi.delete(`/workspaces/${workspaceId}/files${filePath}`);
    },
    onSuccess: (_, filePath) => {
      queryClient.invalidateQueries({ queryKey: ['workspace-files', workspaceId] });
      toast.success('Deleted successfully');
      removeOpenFile(filePath);
      if (selectedItem?.path === filePath) {
        setSelectedItem(null);
      }
    },
    onError: (err) => {
      toastApiError(err, 'Failed to delete file');
    },
  });

  const files = useMemo(() => {
    return [...(data?.files ?? [])].sort((a, b) => {
      if (a.isDirectory !== b.isDirectory) return a.isDirectory ? -1 : 1;
      return a.name.localeCompare(b.name);
    });
  }, [data?.files]);

  const toggleDirectory = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setExpandedPaths((current) => {
      const next = new Set(current);
      if (next.has(file.path)) {
        next.delete(file.path);
      } else {
        next.add(file.path);
      }
      return next;
    });
  };

  const openFile = (file: WorkspaceFileMetadata) => {
    setSelectedItem(file);
    setSelectedFile(file.path);
    addOpenFile(file.path);
  };

  if (isLoading) {
    return <div className={cn('py-1 pr-2 text-xs text-muted-foreground', indentClass(level))}>Loading...</div>;
  }

  if (isError) {
    return <div className={cn('py-1 pr-2 text-xs text-destructive', indentClass(level))}>Could not load files.</div>;
  }

  if (files.length === 0 && level === 0) {
    return <div className="px-4 py-2 text-xs text-muted-foreground">No files in this workspace.</div>;
  }

  return (
    <ul className="space-y-0.5 px-1.5">
      {files.map((file) => {
        const isExpanded = expandedPaths.has(file.path);
        const isSelected = selectedItem?.path === file.path;

        return (
          <ContextMenu key={file.path}>
            <ContextMenuTrigger>
              <li>
                <button
                  type="button"
                  className={cn(
                    'flex h-7 w-full items-center rounded-md pr-2 text-left text-sm transition-colors',
                    isSelected
                      ? 'bg-primary/10 text-primary'
                      : 'text-foreground/80 hover:bg-muted',
                    indentClass(level)
                  )}
                  onClick={() => (file.isDirectory ? toggleDirectory(file) : openFile(file))}
                >
                  {file.isDirectory ? (
                    <>
                      {isExpanded ? (
                        <ChevronDown className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      ) : (
                        <ChevronRight className="mr-1 h-3.5 w-3.5 text-muted-foreground" />
                      )}
                      {isExpanded ? (
                        <FolderOpen className="mr-1.5 h-4 w-4 text-blue-500" />
                      ) : (
                        <Folder className="mr-1.5 h-4 w-4 text-blue-500" />
                      )}
                    </>
                  ) : (
                    <FileIcon className="ml-5 mr-1.5 h-4 w-4 text-muted-foreground" />
                  )}
                  <span className="truncate">{file.name}</span>
                </button>
                {file.isDirectory && isExpanded && <TreeBranch workspaceId={workspaceId} path={file.path} level={level + 1} />}
              </li>
            </ContextMenuTrigger>
            <ContextMenuContent className="w-48">
              {!file.isDirectory && (
                <ContextMenuItem onClick={() => openFile(file)}>
                  <Pencil className="mr-2 h-4 w-4" /> Edit
                </ContextMenuItem>
              )}
              {/* Note: Rename and move functionality to be fully implemented via modals */}
              <ContextMenuItem disabled>
                <Pencil className="mr-2 h-4 w-4" /> Rename
              </ContextMenuItem>
              <ContextMenuSeparator />
              <ContextMenuItem
                className="text-destructive focus:bg-destructive focus:text-destructive-foreground"
                onClick={() => {
                  if (confirm(`Are you sure you want to delete ${file.name}?`)) {
                    deleteMutation.mutate(file.path);
                  }
                }}
              >
                <Trash className="mr-2 h-4 w-4" /> Delete
              </ContextMenuItem>
            </ContextMenuContent>
          </ContextMenu>
        );
      })}
    </ul>
  );
}

function indentClass(level: number) {
  const classes = ['pl-2', 'pl-5', 'pl-8', 'pl-11', 'pl-14', 'pl-16'];
  return classes[Math.min(level, classes.length - 1)];
}

